window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["techniques"]={"updatedAt":"2026-07-14","count":116,"techniques":[{"id":"thai-bach-kiem-quyet","name":"Thái Bạch Kiếm Quyết","cn":"太白剑诀","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Cổ Kiếm Môn","soHuu":["Cổ Kiếm Môn"],"blurb":"Tuyệt học trấn phái của Cổ Kiếm Môn, tại Khê Quốc bài danh đỉnh đỉnh, yêu cầu linh căn cực cao, đệ tử tu vi đại thành thì cùng cấp ít đối thủ.","detail":"Tuyệt học ngự kiếm thuật trấn phái Cổ Kiếm Môn. Tại Khê Quốc nổi danh hàng đầu. Yêu cầu tư chất linh căn cực cao mới có thể tu luyện. Đệ tử Cổ Kiếm Môn một khi tu vi đại thành, nhờ tính công kích siêu cường mà các tu sĩ cùng cấp thường không phải là đối thủ.","congNang":["Ngự kiếm thuật công kích siêu cường, cùng cấp ít đối thủ"],"tabs":{"tienTrinh":[{"chuong":"@c0596","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Hàn Lập nhắc khi cân nhắc ba môn phái","text":"Hàn Lập phân tích ba phái tại Vân Mộng Sơn, nhận định Thái Bạch Kiếm Quyết là tuyệt học trấn phái Cổ Kiếm Môn, bài danh đỉnh đỉnh tại Khê Quốc nhưng yêu cầu linh căn quá cao.","anchor":"tuyệt học trấn phái “Thái Bạch Kiếm Quyết” tại Khê Quốc càng bài danh đỉnh đỉnh"}]},"nguon":["@c0596"]},{"id":"van-tam-thuat","name":"Vấn Tâm Thuật","cn":"問心術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Miêu sư huynh"],"blurb":"Thuật phán đoán thật-giả do Lạc Vân Tông sử dụng khi kiểm tra tân đệ tử nhập môn, dùng kèm Vấn Tâm Phù.","detail":"Phương pháp kiểm tra tâm ý, không phải Mê hồn thuật. Hỏi mười câu, sai ba thì bị loại. Chính xác khoảng 80-90%. Cần phối hợp Vấn Tâm Phù áp lên vai phải người bị kiểm tra. Hàn Lập tự tin thuật này không thể phán đoán được thật lòng hắn.","congNang":["Phán đoán lời nói thật hay giả, chính xác khoảng 80-90%"],"dacDiem":"Không phải Mê hồn thuật, chỉ phán đoán thật-giả, cần Vấn Tâm Phù phối hợp","nguoiTu":[{"ten":"Miêu sư huynh","tuChuong":"@c0598","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0598","loai":"thi triển","importance":"major","giaiDoan":"Kiểm tra tân đệ tử Lạc Vân Tông","text":"Miêu sư huynh thi triển Vấn Tâm Thuật kiểm tra bảy tán tu mới nhập môn, hỏi mười câu mỗi người. Cả bảy đều qua, bao gồm Hàn Lập người tự tin thuật này không thể phát hiện thật lòng hắn.","anchor":"Mặc dù đây chỉ là thuật phán đoán, không thể nói là hoàn toàn chính xác, nhưng cũng đúng khoảng tám chín phần mười"}]},"nguon":["@c0598"]},{"id":"kim-luyen-quyet","name":"Kim Luyện quyết","cn":"金炼诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Kim thuộc tính","soHuu":["Lý sư bá"],"blurb":"Công pháp kim thuộc tính do Lý sư bá của Hỏa Vân Phong tu luyện, nổi danh ở Khê Quốc.","detail":"Công pháp kim thuộc tính, được trung niên đại diện Hỏa Vân Phong viện dẫn khi tranh đệ tử có Đoán kim chi thể, cho thấy Hỏa Vân Phong cũng có khả năng dạy công pháp kim thuộc tính dù chủ yếu tu hỏa thuộc tính.","thuocTinh":"Kim","nguonGoc":"Hỏa Vân Phong, Lạc Vân Tông","nguoiTu":[{"ten":"Lý sư bá","tuChuong":"@c0599","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Được viện dẫn trong tranh chấp đệ tử","text":"Trung niên đại diện Hỏa Vân Phong nhắc đến Kim Luyện quyết của Lý sư bá nổi danh ở Khê Quốc để tranh đệ tử Đoán kim chi thể.","anchor":"Hỏa Vân Phong chúng ta cũng có Lý sư bá với Kim Luyện quyết ở Khê Quốc này cũng rất là nổi danh"}]},"nguon":["@c0599"]},{"id":"huyen-bang-quyet","name":"Huyền Băng Quyết","cn":"玄冰诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Thiên Tuyền Phong","soHuu":["Hàn Lập"],"blurb":"Công pháp thủy thuộc tính do Mộ Phái Linh giao cho Hàn Lập qua ngọc giản khi hắn nhận trông coi dược viên.","detail":"Công pháp tu luyện thủy thuộc tính, được ghi trên ngọc giản và lưu lại cho Hàn Lập bởi Mộ Phái Linh (Trúc Cơ trung kỳ, ngũ sư tỷ Thiên Tuyền Phong) khi nàng giao dược viên cho hắn quản lý. Hàn Lập nhận công pháp này dưới danh nghĩa ngoại môn đệ tử mới của Thiên Tuyền Phong.","nguon":["@c0600"]},{"id":"cau-linh-tran","name":"Câu Linh Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp ẩn nặc cấp cao, có thể che giấu được cả tu sĩ Nguyên Anh Kỳ. Hàn Lập bắt đầu nghiên cứu phương pháp bố trí từ ngọc giản đen.","detail":"Hàn Lập lấy ngọc giản đen chứa phương pháp bố trí Câu Linh Trận ra nghiên cứu, dự định bố trí bên ngoài động phủ bí mật làm tầng phòng hộ thứ hai. Khi hoàn thành, cho dù là tu sĩ Nguyên Anh Kỳ cũng không cách nào nhìn ra điều khác thường.","congNang":["Ẩn nặc cấp cao, che giấu được cả tu sĩ Nguyên Anh Kỳ"],"nguon":["@c0601"],"tabs":{"tienTrinh":[{"chuong":"@c0601","loai":"xuất hiện","importance":"normal","giaiDoan":"Bắt đầu nghiên cứu","text":"Hàn Lập lấy ngọc giản đen chứa phương pháp bố trí Câu Linh Trận ra nghiên cứu, dự định bố trí bên ngoài động phủ làm tầng phòng hộ thứ hai có thể che mắt cả Nguyên Anh Kỳ.","anchor":"Đến lúc đó cho dù là tu sĩ Nguyên Anh Kỳ, cũng không cách nào nhìn ra cái gì khác thường"}]}},{"id":"tat-phong-cuu-bien","name":"Tật Phong Cửu Biến","cn":"疾風九變","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Yêu tộc","soHuu":[],"blurb":"Công pháp yêu tộc ghi trên sách da thú, chuyên cho yêu cầm tu luyện, gồm bộ pháp quyết, thân pháp và hai mật thuật Nặc Phong thuật cùng Huyết Ảnh Độn.","detail":"Pháp quyết và thân pháp hoàn toàn dành riêng cho yêu thú, nhân loại tu luyện sẽ bạo thể mà chết. Chỉ hai mật thuật kèm theo (Nặc Phong thuật và Huyết Ảnh Độn) có thể được nhân loại tham khảo hoặc tu luyện.","thuocTinh":"Phong","nguonGoc":"Cổ văn yêu tộc ghi trên miếng sách da thú","dacDiem":"Nhân loại không thể tu luyện pháp quyết và thân pháp, chỉ có thể dùng hai mật thuật kèm theo","congNang":["Bộ pháp quyết và thân pháp cho yêu cầm","Kèm hai mật thuật: Nặc Phong thuật và Huyết Ảnh Độn"],"tabs":{"tienTrinh":[{"chuong":"@c0602","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập giải mã sách da thú","text":"Hàn Lập học cổ văn yêu tộc, dịch miếng sách da thú phát hiện công pháp Tật Phong Cửu Biến gồm pháp quyết, thân pháp và hai mật thuật.","anchor":"công pháp yêu tộc gọi là Tật Phong Cửu Biến"}]},"nguon":["@c0602"]},{"id":"huyet-anh-don","name":"Huyết Ảnh Độn","cn":"血影遁","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Yêu tộc","soHuu":["Hàn Lập"],"blurb":"Mật thuật độn thuật từ Tật Phong Cửu Biến, mượn lực lượng máu huyết hóa huyết ảnh bắn ra ngoài trăm dặm trong nháy mắt, tốc độ vượt xa lôi độn.","detail":"Ba đặc điểm nguy hiểm: không khống chế được khoảng cách (thi triển là lao thẳng trăm dặm); tiêu hao rất nhiều tinh huyết (máu không đủ thì da thịt nổ tung hóa huyết vụ mà chết); bắt buộc phải có đôi cánh để duy trì thăng bằng (không có cánh thì đầu đập đất hoặc đảo quanh tại chỗ). Hàn Lập nhận ra Phong Lôi Sí đáp ứng điều kiện cánh, kiêm tu nửa năm tự cảm nắm được nhưng chưa dám thực hành.","nguonGoc":"Mật thuật thứ hai trong Tật Phong Cửu Biến (công pháp yêu tộc)","dacDiem":"Không khống chế khoảng cách; tiêu hao tinh huyết cực lớn; bắt buộc có cánh","uyLuc":"Tốc độ vượt xa lôi độn, tức thời bắn xa trăm dặm","congNang":["Độn thuật chạy trốn tức thời ngoài trăm dặm","Mượn lực lượng máu huyết hóa huyết ảnh"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0602","tangDatToi":"Kiêm tu nửa năm, nắm được lý thuyết","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0602","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và kiêm tu","text":"Hàn Lập giải mã sách da thú phát hiện Huyết Ảnh Độn, nhận ra Phong Lôi Sí đáp ứng điều kiện cánh. Kiêm tu nửa năm, tự cảm nắm được nhưng chưa dám thực hành vì tốn hao máu huyết.","anchor":"Huyết Ảnh Độn này kỳ thật chính là một loại độn thuật quỷ dị mượn lực lượng máu huyết trong nháy mắt chạy trốn ngoài trăm dặm"}]},"nguon":["@c0602"]},{"id":"me-tung-tran","name":"Mê Tung trận","cn":"迷踪阵","aliases":["Ngũ Hành Mê Tung trận"],"loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp dùng trận kỳ bố trí mê trận vây bắt mục tiêu, nhóm Khuê Hoán mượn từ một nội môn sư huynh để bắt dị chủng Tuyết Vân Hồ.","detail":"Nhóm Khuê Hoán mượn được bộ Mê Tung trận pháp kỳ từ một vị nội môn sư huynh, dùng để bố trí trận nhỏ vây bắt dị chủng Tuyết Vân Hồ tại Lục Tung chiểu trạch. Cần đủ người mới vận hành được trận pháp.","congNang":["Bố trí mê trận vây bắt mục tiêu"],"tabs":{"tienTrinh":[{"chuong":"@c0603","loai":"xuất hiện","importance":"normal","giaiDoan":"Được mượn để bắt Tuyết Vân Hồ","text":"Nhóm Khuê Hoán mượn được bộ Mê Tung trận pháp kỳ từ một nội môn sư huynh để bố trí trận vây bắt dị chủng Tuyết Vân Hồ, nhưng thiếu người vận hành nên mời Hàn Lập tham gia.","anchor":"mượn được từ một vị nội môn sư huynh Mê Tung trận pháp kỳ"}]},"nguon":["@c0603"]},{"id":"chuong-nhan-phap","name":"Chướng Nhãn pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Tuyết Vân Hồ"],"blurb":"Thuật che mắt, Tuyết Vân Hồ sử dụng để che giấu hình dạng khi độn thổ, đánh lừa thị giác đám tu sĩ.","detail":"Tuyết Vân Hồ dùng để lén lút độn nhập vào đất trốn thoát khi bị nhóm Khuê Hoán bao vây. Che giấu hình dạng khi di chuyển trong lòng đất, khiến bốn đệ tử Ẩn Kiếm Phong không phát hiện được, chỉ có thần thức Hàn Lập mới nhận ra.","thuocTinh":"Không rõ","congNang":["Che giấu hình dạng khi độn thổ, đánh lừa thị giác người quan sát"],"nguoiTu":[{"ten":"Tuyết Vân Hồ","tuChuong":"@c0606","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0606","loai":"thi triển","importance":"normal","giaiDoan":"Tuyết Vân Hồ dùng để trốn thoát","text":"Tuyết Vân Hồ sử dụng Chướng Nhãn pháp che mắt đám tu sĩ Ẩn Kiếm Phong, lén lút độn nhập vào đất trốn thoát sau khi giả chết.","anchor":"yêu hồ kia dùng Chướng Nhãn pháp (thuật che mắt), lén lut độn nhập vào đất"}]},"nguon":["@c0606"]},{"id":"tho-don-thuat","name":"Thổ Độn Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thổ","soHuu":["Hàn Lập"],"blurb":"Thần thông thuộc tính Thổ, Hàn Lập thi triển qua khí linh Thổ thuộc tính trong Ngọc Như Ý, triệu tiểu lang vàng mở đường xuyên núi đá.","detail":"Hàn Lập cầm Ngọc Như Ý phóng xuất khí linh Thổ thuộc tính, triệu ra tiểu lang vàng mở đường xuyên qua lòng núi đá để truy đuổi Tuyết Vân Hồ mà không kinh động yêu hồ. Giữ khoảng cách vài chục trượng bám sát bạch quang của yêu hồ.","thuocTinh":"Thổ","congNang":["Xuyên qua đất đá di chuyển trong lòng núi, tiểu lang vàng mở đường phía trước"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0606","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0606","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng truy đuổi Tuyết Vân Hồ trong núi đá","text":"Hàn Lập cầm Ngọc Như Ý phóng xuất khí linh Thổ thuộc tính triệu tiểu lang vàng mở đường xuyên núi đá, bám sát bạch quang của Tuyết Vân Hồ ở khoảng cách vài chục trượng.","anchor":"phóng xuất ra khí linh Thổ thuộc tính trong cổ bảo của Ngọc Như Ý"}]},"nguon":["@c0606"]},{"id":"hap-linh-thach","name":"Hấp Linh thạch","cn":"吸灵石","aliases":["Thanh Kim thạch"],"loai":"khac","loaiLabel":"Tài liệu luyện khí","phamCap":"Trân quý, gần thất truyền","hePhai":"","soHuu":[],"blurb":"Loại đá đặc biệt miễn dịch linh lực, tự phục hồi vết thương, là tài liệu luyện khí trân quý cực hiếm ngoài tự nhiên.","detail":"Còn gọi là Thanh Kim thạch, là loại tài liệu luyện khí vô cùng trân quý. Kiếm mang công kích lên bề mặt không để lại vết tích, phi kiếm bắn vào chỉ tạo lỗ nhỏ sâu một tấc rồi tự liền lại. Ngoài dùng lực cực mạnh phá hỏng thì không gì tác động được, kể cả linh lực. Ngoài tự nhiên vô cùng hiếm, gần như không còn mấy người biết đến, gần thất truyền. Thạch thất nơi hắc y thiếu phụ ẩn tu được xây hoàn toàn bằng loại đá này, vách tường thô sơ lồi lõm.","nguon":["@c0607"]},{"id":"u-sat-quyet","name":"U Sát quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Hắc y thiếu phụ"],"blurb":"Công pháp chủ tu của Hắc y thiếu phụ, tu luyện tốc độ nhanh và uy lực mạnh nhưng có khuyết điểm trí mạng: khi đại thành tiến vào Nguyên Anh kỳ thì sát tính bùng phát không kiểm soát.","detail":"U Sát quyết khác biệt hoàn toàn với công pháp tu luyện bình thường. Ưu điểm là tốc độ tu luyện cực nhanh, uy lực thần kỳ. Tuy nhiên khuyết điểm trí mạng: khi đại thành và tiến vào Nguyên Anh kỳ, người tu sẽ mất kiểm soát sát tính, tâm tính thay đổi hoàn toàn. Hắc y thiếu phụ tu đại thành đã tạo ra mưa gió trong Tu Tiên giới, bị nhiều tu sĩ Nguyên Anh kỳ liên thủ vây đánh trọng thương, phế mất một cánh tay.","thuocTinh":"","nguonGoc":"","yeuCau":"","uyLuc":"Uy lực thần kỳ, tu luyện tốc độ nhanh","dacDiem":"Đại thành sẽ bùng phát sát tính không thể kiểm soát, thay đổi tâm tính","congNang":["Tu luyện tốc độ cực nhanh","Uy lực mạnh vượt trội công pháp thường","Khuyết điểm: đại thành tiến Nguyên Anh kỳ sát tính bùng phát không kiểm soát"],"nguoiTu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","tangDatToi":"Nguyên Anh trung kỳ (đại thành)","trangThai":"sát tính bùng phát, tự giam"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hé lộ lai lịch và khuyết điểm trí mạng","text":"Hắc y thiếu phụ tự bạch tu U Sát quyết đại thành tiến Nguyên Anh kỳ, sát tính bùng phát không kiểm soát, gây mưa gió tu tiên giới bị vây đánh phế tay.","anchor":"công pháp chủ tu “U Sát quyết” của ta vô cùng khác với công pháp tu luyện bình thường"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"huyen-thuat-yeu-ho","name":"Huyễn thuật","cn":"幻术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu hồ","soHuu":["Yêu hồ (Bạch hồ)"],"blurb":"Thần thông của yêu hồ, tạo phân thân ảo ảnh chịu đòn thay thân thật, kết hợp ám kích từ chỗ trống.","detail":"Yêu hồ tạo hình ảnh phân thân giả bị kiếm khí xuyên thủng để lừa đối phương, đồng thời bắn ngân ti ám kích từ vị trí khác. Hàn Lập nhận ra đó là huyễn thuật sau khi kiếm khí xuyên qua mà không có cảm giác trúng đích.","congNang":["Tạo ảo ảnh thân thể chịu đòn thay, kết hợp ám kích bất ngờ"],"nguon":["@c0611"]},{"id":"phan-sac-huong-vu","name":"Phấn sắc hương vụ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu hồ","soHuu":["Yêu hồ (Bạch hồ)"],"blurb":"Yêu hồ phun phấn sắc hương vụ từ miệng, tràn ngập hơn nửa thạch thất, che khuất thân hình.","detail":"Thần thông phun từ miệng một mảng lớn phấn sắc hương vụ che khuất diện rộng. Yêu hồ dùng để che thân khi bị Ngân sắc cự lang uy hiếp.","congNang":["Phun vụ khí diện rộng che thân"],"nguon":["@c0611"]},{"id":"ma-dong","name":"Ma đồng","cn":"魔瞳","loai":"bi-thuat","loaiLabel":"Thiên phú","phamCap":"Không rõ","hePhai":"Tứ đồng linh hồ (Tuyết Vân Hồ đại thành)","soHuu":[],"blurb":"Thiên phú của Tứ đồng linh hồ, có thể vô hình giết chết kẻ địch trong lúc cười nói.","detail":"Khi Tuyết Vân Hồ tu vi đại thành sẽ biến thành Tứ đồng linh hồ, sở hữu thiên phú ma đồng. Bề ngoài giống Tuyết Vân Hồ bình thường nhưng khi thi triển công pháp sẽ bị Ngân Nguyệt lang tộc nhận ra. Bị Ngân Nguyệt lang tộc thiên sinh khắc chế.","thuocTinh":"Linh hồn","nguonGoc":"Thiên phú bẩm sinh của Tứ đồng linh hồ","dacDiem":"Vô hình giết địch trong lúc cười nói, bị Ngân Nguyệt lang tộc khắc chế","congNang":["Vô hình giết chết kẻ địch trong lúc cười nói"],"nguon":["@c0612"]},{"id":"mat-thuat-de-thang-tu-vi","name":"Mật thuật đề thăng tu vi tạm thời","cn":"","loai":"bi-thuat","loaiLabel":"Mật thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt lang tộc","soHuu":["Ngân Nguyệt"],"blurb":"Mật thuật của Ngân Nguyệt lang tộc, tạm thời đề thăng tu vi lên thất-bát cấp yêu thú.","detail":"Ngân Nguyệt sử dụng mật thuật này để tạm thời đưa tu vi từ yêu thú cấp thấp lên thất cấp thậm chí bát cấp. Hiệu quả chỉ tạm thời, sau một thời gian tu vi hạ xuống, muốn biến hình người lại phải đợi ít nhất một tháng.","thuocTinh":"Không rõ","nguonGoc":"Mật thuật Ngân Nguyệt lang tộc","dacDiem":"Hiệu quả tạm thời, cần ít nhất 1 tháng hồi phục trước khi dùng lại","congNang":["Tạm thời đề thăng tu vi lên thất-bát cấp yêu thú"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0612","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0612","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Ngân Nguyệt tiết lộ","text":"Ngân Nguyệt cho biết có mật thuật tạm đưa tu vi lên thất-bát cấp yêu thú nhưng sau đó hạ xuống, muốn biến hình người lại cần ít nhất một tháng.","anchor":"có thể tạm thời đưa tu vi đề thăng lên trình độ yêu thú thất cấp thậm chí bát cấp"}]},"nguon":["@c0612"]},{"id":"thon-phe-linh-hon","name":"Thôn phệ linh hồn","cn":"","aliases":["Linh hồn cắn nuốt"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Bí thuật đoạt xá chiếm thân xác khác, đại giá là mất hơn phân nửa tu vi hồn khí bản thân.","detail":"Ngân Nguyệt từng thi triển thuật này để đoạt xá. Hậu quả: tu vi hồn khí sau đoạt xá mất hơn phân nửa.","congNang":["Đoạt xá chiếm thân xác khác"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0613","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0613","loai":"nhắc tới","importance":"normal","giaiDoan":"Ngân Nguyệt nhắc lại hậu quả","text":"Ngân Nguyệt xác nhận đã thi triển linh hồn cắn nuốt để đoạt xá, hậu quả mất hơn phân nửa tu vi hồn khí.","anchor":"sau khi thi triển linh hồn cắn nuốt, tu vi hồn khí bản thân sau khi đoạt xá đã mất hơn phân nửa"}]},"nguon":["@c0613"]},{"id":"thong-minh-linh-te","name":"Thông Minh Linh Tê","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Tống sư tổ"],"blurb":"Thần thông độc đáo của Tống sư tổ, có khả năng dò xét tâm thần cực mạnh, phát hiện mọi bí mật giấu diếm. Trừ vài cao thủ Kết Đan ra không ai có thể chống lại.","detail":"Thần thông thi triển qua ánh mắt, khiến đối tượng cảm giác toàn bộ thể xác và tinh thần bị nhìn thấu. Uy lực mạnh đến mức trừ hai vị sư thúc và bạch tu lão giả Kết Đan Kỳ ra, không ai có thể ngăn trở. Lần thi triển này phát hiện Đỗ Đông có giấu diếm trong khi Hàn Lập vượt qua nhờ Đại Diễn Quyết bảo vệ tâm thần.","thuocTinh":"Dò xét tâm thần","uyLuc":"Cực mạnh, chỉ vài Kết Đan cao thủ chống được","dacDiem":"Thi triển qua ánh mắt trong suốt, khiến đối tượng cảm giác bị nhìn thấu toàn bộ","congNang":["Dò xét tâm thần, phát hiện mọi bí mật giấu diếm của đối tượng"],"nguoiTu":[{"ten":"Tống sư tổ","tuChuong":"@c0623","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0623","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Tống sư tổ thi triển trên Hàn Lập và Đỗ Đông để kiểm tra 24 đệ tử nổi danh. Phát hiện Đỗ Đông có vấn đề, Hàn Lập vượt qua nhờ Đại Diễn Quyết.","anchor":"Thông Minh Linh Tê thần thông của Tống sư muội phát ra rất lợi hại"}]},"nguon":["@c0623"]},{"id":"thanh-nguyen-kiem-quyet","name":"Thanh Nguyên Kiếm Quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kiếm quyết Hàn Lập tĩnh tâm khổ tu trong động phủ dược viên.","detail":"Hàn Lập tu luyện Thanh Nguyên Kiếm Quyết trong ba tháng khổ tu tại động phủ dược viên.","nguon":["@c0623"]},{"id":"hoa-dieu-thuat","name":"Hỏa Điểu thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kỹ thuật bắt quyết biến Hỏa đạn phù thành hơn mười con chim lửa cỡ nắm tay, dùng thần niệm điều khiển tấn công linh hoạt từ bốn phương tám hướng.","detail":"Hàn Lập ném Hỏa đạn phù rồi bắt quyết biến hỏa cầu thành hơn mười con Hỏa Điểu lớn nhỏ cỡ nắm tay, bay múa xoay quanh. Dùng thần niệm điều khiển chúng bao vây tấn công đối phương từ tứ phương bát hướng, phá vỡ vòng bảo hộ thủy thuộc tính.","congNang":["Biến hỏa cầu từ Hỏa đạn phù thành Hỏa Điểu, dùng thần niệm điều khiển tấn công linh hoạt đa hướng"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0625","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0625","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển tại Thí Kiếm Đại Hội","text":"Hàn Lập bắt quyết biến Hỏa đạn phù thành hơn mười con Hỏa Điểu, dùng thần niệm điều khiển bao vây nữ tu Bách Xảo Viện, phá vỡ vòng bảo hộ thủy thuộc tính buộc đối phương nhận thua.","anchor":"hóa thành hơn mười con chim lửa lớn nhỏ cỡ nắm tay, bay múa xoay quanh"}]},"nguon":["@c0625"]},{"id":"quy-sat-quyet","name":"Quỷ Sát Quyết","cn":"鬼煞诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Tu sĩ áo vàng họ Việt"],"blurb":"Công pháp tu luyện của tu sĩ họ Việt, tiến bộ đáng kể nhờ tu luyện gần thánh thụ tại cấm địa năm sáu mươi năm, tạo sát khí kinh người trên mặt.","detail":"Tu sĩ Kết Đan họ Việt tu luyện Quỷ Sát Quyết trong thời gian trấn thủ Tam Phái Cấm Địa, nhờ gần thánh thụ mà công pháp tiến triển không ít, sát khí trên mặt kinh người.","congNang":["Tạo sát khí kinh người trên mặt người tu"],"nguoiTu":[{"ten":"Tu sĩ áo vàng họ Việt","tuChuong":"@c0626","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Tu sĩ họ Việt tu luyện gần thánh thụ","text":"Tu sĩ trung niên Bách Xảo Viện nhận xét Quỷ Sát Quyết của Việt sư huynh tiến triển không ít nhờ tu luyện gần thánh thụ cấm địa.","anchor":"Quỷ Sát Quyết của Việt sư huynh tựa hồ tiến triển không ít"}]},"nguon":["@c0626"]},{"id":"cuu-linh-kiem-the","name":"Cửu Linh Kiếm Thể","cn":"九灵剑体","loai":"khac","loaiLabel":"Linh thể đặc thù","phamCap":"Tam đại kiếm tu linh thể","hePhai":"Kiếm tu","soHuu":["Mạnh Địch"],"blurb":"Một trong tam đại kiếm tu linh thể trong tu tiên giới. Mạnh Địch sở hữu, bằng vào phi kiếm đỉnh cấp pháp khí tung hoành vô đối thủ tại Thí Kiếm Đại Hội.","detail":"Cửu Linh Kiếm Thể được xưng là một trong tam đại kiếm tu linh thể trong tu tiên giới. Người sở hữu có uy lực phi kiếm tuyệt đối, Mạnh Địch nhờ đó cùng phi kiếm đỉnh cấp tung hoành không đối thủ, đoạt quán quân Thí Kiếm Đại Hội.","congNang":["Uy lực phi kiếm tuyệt đối, tung hoành không đối thủ"],"nguoiTu":[{"ten":"Mạnh Địch","tuChuong":"@c0626","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện tại Thí Kiếm Đại Hội","text":"Mạnh Địch dùng Cửu Linh Kiếm Thể cùng phi kiếm đỉnh cấp tung hoành vô đối thủ, đoạt quán quân tuyệt đối.","anchor":"\"Cửu Linh Kiếm Thể\" được xưng là một trong tam đại kiếm tu linh thể trong tu tiên giới"}]},"nguon":["@c0626"]},{"id":"cam-che-cam-dia-ba-phai","name":"Cấm chế cấm địa ba phái","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp / Cấm chế","phamCap":"Do Nguyên Anh Kỳ tu sĩ thiết lập","hePhai":"","soHuu":[],"blurb":"Cấm chế nhiều tầng do mấy vị sư thúc Nguyên Anh Kỳ ba phái cùng thiết lập, bảo vệ Tam Phái Cấm Địa. Phong tỏa thần thức, chặn ở hơn mười trượng, cần lệnh bài vàng chuyên dụng mới mở được.","detail":"Cấm chế bao gồm nhiều tầng vách bao bọc cửa đá dày đặc chú văn. Ngăn thần thức người vào chỉ vươn hơn mười trượng. Chỉ mở được nhất thời bằng lệnh bài vàng chuyên dụng, tạo thông đạo vài trượng. Hàn Lập (Trúc Cơ hậu kỳ) nhận ra pháp trận cực kỳ lợi hại.","congNang":["Phong tỏa thần thức","Cấm chế đa tầng bảo vệ cửa đá","Chỉ mở nhất thời bằng lệnh bài vàng"],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"xuat-hien","importance":"normal","giaiDoan":"Đoàn người vượt qua cấm chế vào cấm địa","text":"Thần thức Hàn Lập bị cấm chế chặn ở hơn mười trượng. Tu sĩ họ Việt dùng lệnh bài vàng mở cấm chế nhiều tầng do Nguyên Anh Kỳ thiết lập, tạo thông đạo cho mọi người bay vào.","anchor":"Cấm địa này là mấy vị sư thúc Nguyên Anh Kỳ ba phái cùng làm phép thiết lập"}]},"nguon":["@c0626"]},{"id":"kiem-khi-hoa-to","name":"Kiếm khí hóa tơ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Cảnh giới kiếm tu","phamCap":"Cảnh giới kiếm tu tối cao","hePhai":"","soHuu":["Đồng tử họ Lam"],"blurb":"Cảnh giới cực cao của kiếm tu, kiếm khí luyện hóa thành tuyến tơ tằm bao bọc hàn khí, có thể tùy tâm sở dục hóa kiếm thành tơ, lấy một kiếm phá vạn pháp.","detail":"Đồng tử Lam sư thúc (Nguyên Anh sơ kỳ) thi triển: bắn ra tuyến tơ tằm màu đỏ được bao bọc bởi hàn khí lạnh lẽo, hạ gục tu sĩ Kết Đan trong nháy mắt. Chỉ có Hàn Lập dùng thần thức mới phát hiện. Lần đầu Hàn Lập tận mắt chứng kiến cảnh giới kiếm tu này.","congNang":["Kiếm khí luyện thành tơ, phá vạn pháp bằng một kiếm","Chế phục tu sĩ Kết Đan trong nháy mắt, người thường không thể phát hiện"],"nguoiTu":[{"ten":"Đồng tử họ Lam","tuChuong":"@c0627","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Đồng tử Lam sư thúc bắn tuyến tơ tằm đỏ bao bọc hàn khí hạ gục nho sinh Kết Đan trong nháy mắt. Hàn Lập là người duy nhất phát hiện bằng thần thức, lần đầu chứng kiến cảnh giới kiếm tu tối cao.","anchor":"có thể tùy tâm sở dục hóa kiếm thành tơ, có thể lấy một kiếm phá vạn pháp"}]},"nguon":["@c0627"]},{"id":"thai-bach-hoa-khi-thu","name":"Thái bạch hóa khí thủ","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Cổ Kiếm Môn","soHuu":["Nho sinh"],"blurb":"Công pháp của Cổ Kiếm Môn, hóa khí thành bàn tay lớn mịt mờ bắt người. Nho sinh họ Bạch tu luyện rất tốt, dùng quang thủ ép vỡ kiếm khí Luyện Khí Kỳ dễ dàng.","detail":"Bạch quang lóe trên người, tạo quang thủ mịt mờ nhắm bắt mục tiêu. Khi nho sinh bạo phát thi triển nhắm Mạnh Địch, kiếm khí Luyện Khí Kỳ của Mạnh Địch bị ép vỡ vụn. Đồng tử xác nhận đây là công pháp bổn môn, nho sinh tu luyện rất tốt. Quang thủ sau đó bị đồng tử hóa giải, tan thành điểm sáng biến mất.","congNang":["Hóa khí thành bàn tay lớn bắt người","Cấp Kết Đan, ép vỡ kiếm khí Luyện Khí Kỳ dễ dàng"],"nguoiTu":[{"ten":"Nho sinh","tuChuong":"@c0627","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"thi triển","importance":"normal","giaiDoan":"Nho sinh bạo phát","text":"Nho sinh họ Bạch thi triển khi bị lật tẩy, bạch quang lóe trên người tạo quang thủ nhắm bắt Mạnh Địch. Bị đồng tử hóa giải, quang thủ tan thành điểm sáng.","anchor":"Ngươi đem Thái bạch hóa khí thủ của bổn môn tu luyện quả thật rất tốt"}]},"nguon":["@c0627"]},{"id":"dai-la-thien-huyen-quyet","name":"Đại La Thiên Huyễn Quyết","cn":"大罗天幻诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Trấn phái pháp quyết","hePhai":"Thiên Huyễn Tông","soHuu":["Đỗ Đông"],"blurb":"Trấn phái pháp quyết của Thiên Huyễn Tông, thiên hạ đệ nhất ẩn nặc công pháp. Cho phép biến đổi hình thể, che giấu tu vi thật.","detail":"Đỗ Đông thi triển biến hóa thành cự hán cao hai trượng, mặt hiện phù văn đen, mắt xanh biếc, tu vi từ Trúc Cơ tăng lên Kết Đan Trung Kỳ. Hàn Lập nhận xét nếu nói về ẩn nặc công pháp thì Thiên Huyễn Tông tại Thiên Nam xưng đệ nhất. Kết Đan Hậu Kỳ trở lên mới có thể nhìn thấu.","thuocTinh":"Ẩn nặc, biến hóa hình thể","nguonGoc":"Trấn phái Thiên Huyễn Tông","uyLuc":"Che giấu tu vi thật, biến đổi hình thể, Kết Đan Hậu Kỳ mới nhìn thấu","dacDiem":"Ẩn nặc tàng hình, biến đổi hình thể, nâng tu vi biểu hiện","nguoiTu":[{"ten":"Đỗ Đông","tuChuong":"@c0630","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Ẩn nặc tàng hình, che giấu tu vi thật","Biến đổi hình thể (hóa cự hán hai trượng)","Nâng tu vi biểu hiện bên ngoài"],"tabs":{"tienTrinh":[{"chuong":"@c0630","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Đỗ Đông thi triển, hóa cự hán hai trượng mắt xanh biếc, tu vi tăng lên Kết Đan Trung Kỳ. Hàn Lập nhận xét là thiên hạ đệ nhất ẩn nặc công pháp.","anchor":"Đại La Thiên Huyễn Quyết chính xác là danh bất hư truyền, không hổ là trấn phái pháp quyết của quý tông"}]},"nguon":["@c0630"]},{"id":"thien-ho-me-linh-dai-phap","name":"Thiên Hồ Mê Linh Đại Pháp","cn":"天狐迷灵大法","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Hồ tộc","soHuu":["Ngân Nguyệt"],"blurb":"Hồ tộc công pháp cho phép tạo phân thân giả có thể chịu chết thay chủ, lừa được tu sĩ Kết Đan Trung Kỳ.","detail":"Ngân Nguyệt thi triển tạo phân thân giả hình Hàn Lập, có tim có máu, lừa được Đỗ Đông (Kết Đan Trung Kỳ) tưởng đã giết xong. Hàn Lập nói Kết Đan Hậu Kỳ thì không lừa được. Là Hồ tộc công pháp nhưng Ngân Nguyệt tiền thân là Ngân Lang tộc, rất kỳ lạ. Hóa thân thuật không thể kéo dài, chỉ dùng ứng phó nhất thời.","thuocTinh":"Ảo thuật, phân thân","nguonGoc":"Hồ tộc công pháp","uyLuc":"Tạo phân thân giả chịu chết thay chủ, lừa được Kết Đan Trung Kỳ","dacDiem":"Hoá thân thuật không thể kéo dài, chỉ ứng phó nhất thời","nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0630","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Tạo hoá thân/phân thân giả có thể chịu chết thay chủ","Lừa được Kết Đan Trung Kỳ, Kết Đan Hậu Kỳ thì bị nhìn thấu"],"tabs":{"tienTrinh":[{"chuong":"@c0630","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Ngân Nguyệt tạo phân thân giả hình Hàn Lập, lừa Đỗ Đông tưởng đã giết được Hàn Lập. Hàn Lập nhận xét còn cao hơn Đại La Thiên Huyễn Quyết.","anchor":"Thiên Hồ Mê Linh Đại Pháp của ta có phải còn cao hơn cả Đại La Thiên Huyễn Quyết kia không"}]},"nguon":["@c0630"]},{"id":"phu-than-dai-phap","name":"Phụ Thân Đại Pháp","cn":"附身大法","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Thiên Sát Chân Quân","Cực Âm Lão Tổ"],"blurb":"Công pháp ma đạo cho phép phụ thân vào người khác, chiếm thân thể để chiến đấu. Cần chuẩn bị cực kỳ phức tạp trước khi phụ thân.","detail":"Thiên Sát Chân Quân thi triển qua thân xác lão giả tóc rối: bàn tay bành trướng tử hồng biến thành yêu trảo tím. Hàn Lập nhận ra cùng loại với phụ thân thuật Cực Âm Lão Tổ từng dùng nhưng phương pháp hơi khác. Cần chuẩn bị phức tạp trước, có thể kích hoạt qua trung gian từ xa.","congNang":["Phụ thân vào người khác, chiếm thân thể chiến đấu"],"nguoiTu":[{"ten":"Thiên Sát Chân Quân","tuChuong":"@c0631","tangDatToi":"","trangThai":"thi triển"},{"ten":"Cực Âm Lão Tổ","tuChuong":"@c0631","tangDatToi":"","trangThai":"từng dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0631","loai":"thi triển","importance":"major","giaiDoan":"Thiên Sát Chân Quân phụ thân lão giả tóc rối","text":"Thiên Sát Chân Quân kích hoạt phụ thân thuật đã cài sẵn trong lão giả tóc rối, bàn tay bành trướng tử hồng tấn công Hỏa Long Đồng Tử. Hàn Lập nhận ra cùng loại với thuật Cực Âm Lão Tổ từng dùng.","anchor":"lập tức hiện lên hình ảnh Cực Âm Lão Tổ từng thi triển qua “Phụ Thân Đại Pháp”"}]},"nguon":["@c0631"]},{"id":"thanh-nguyen-kiem-quang","name":"Thanh Nguyên Kiếm Quang","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kiếm quang mạnh mẽ Hàn Lập sử dụng, đủ sức phá vỡ kim chúc quang tráo bảo hộ Linh Nhãn Chi Thụ.","detail":"Hàn Lập dùng Thanh Nguyên Kiếm Quang bổ quang tráo kim sắc bảo hộ Linh Nhãn Chi Thụ ra một lỗ to để rời đi.","congNang":["Phá được kim chúc quang tráo bảo hộ Linh Nhãn Chi Thụ"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0632","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0632","loai":"thi triển","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Hàn Lập dùng Thanh Nguyên Kiếm Quang bổ quang tráo kim sắc ra lỗ lớn để thoát ra ngoài.","anchor":"quang tráo trực tiếp bị Thanh Nguyên Kiếm Quang bổ ra một cái lỗ to"}]},"nguon":["@c0632"]},{"id":"dai-tran-tran-phai","name":"Đại trận trấn phái","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lạc Vân Tông","soHuu":["Lạc Vân Tông"],"blurb":"Trận pháp trấn phái của Lạc Vân Tông, từng được mở ra khi các Nguyên Anh của tông kết anh năm xưa để bảo vệ.","detail":"Lữ sư đệ nhắc lại khi hai vị Nguyên Anh kết anh năm xưa, tông môn đã phong tỏa cả ngọn núi và mở đại trận trấn phái để bảo hộ quá trình kết anh.","congNang":["Bảo hộ quá trình kết anh, phong tỏa ngọn núi"],"tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"nhắc tới","importance":"bridge","giaiDoan":"Được nhắc lại","text":"Lữ sư đệ nhắc lại khi hai vị Nguyên Anh kết anh năm xưa, tông môn đã mở đại trận trấn phái.","anchor":"ngay cả đại trận trấn phái cũng mở ra"}]},"nguon":["@c0635"]},{"id":"tam-ma-can-tra","name":"Tâm ma cắn trả","cn":"","loai":"khac","loaiLabel":"Hiện tượng tu luyện","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Bước cuối cùng trong quá trình kết Nguyên Anh, người kết anh phải đối mặt với tâm ma huyễn hóa ra nỗi sợ lớn nhất của mình.","detail":"Thử thách tâm thần ở giai đoạn cuối kết Nguyên Anh. Người kết anh cảm nhận như trải qua mấy tháng đến mấy năm, nhưng thực tế bên ngoài chỉ một chút thời gian. Càng sợ cái gì tâm ma càng huyễn hóa ra cái đó. Lữ sư đệ (Nguyên Anh Lạc Vân Tông) phải dùng Định Linh Đan mới sống sót qua.","congNang":["Thử thách tâm thần, huyễn hóa nỗi sợ hãi lớn nhất của người kết anh"],"dacDiem":"Thời gian chủ quan kéo dài mấy tháng đến mấy năm, thời gian thực rất ngắn","tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ cơ chế","text":"Trình sư huynh và Lữ sư đệ giải thích cơ chế tâm ma cắn trả khi kết anh: càng sợ cái gì càng huyễn hóa ra cái đó, Lữ sư đệ phải dùng Định Linh Đan mới vượt qua.","anchor":"Tâm ma cắn trả, cơ hồ là ngươi càng sợ hãi cái gì, trong lòng ngươi lại càng huyễn hóa ra cái đó"}]},"nguon":["@c0635"]},{"id":"cam-than-thuat","name":"Cấm thần thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật cấm chế mà Hàn Lập dự định hạ lên người Mộ Phái Linh trước khi chính thức nhận nàng làm thiếp, nhằm ngăn nàng phản bội và tiết lộ bí mật.","detail":"Hàn Lập nêu điều kiện rằng nếu Mộ Phái Linh thật sự làm thiếp thì hắn phải hạ cấm thần thuật lên người nàng. Mục đích là phòng ngừa phản bội và ngăn tiết lộ bí mật của hắn.","congNang":["Khống chế đối tượng, ngăn phản bội và tiết lộ bí mật của người hạ thuật"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0641","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0641","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nêu điều kiện hạ cấm thần thuật","text":"Hàn Lập nói sẽ hạ cấm thần thuật lên người Mộ Phái Linh nếu nàng chọn thật sự làm thiếp, để phòng phản bội và giữ bí mật.","anchor":"trước khi trở thành thiếp của ta thì ta sẽ phải hạ cấm thần thuật trên người ngươi"}]},"nguon":["@c0641"]},{"id":"cong-phap-giu-nguyen-am","name":"Công pháp giữ nguyên âm của Mộ Phái Linh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Mộ Phái Linh"],"blurb":"Công pháp Mộ Phái Linh đang tu luyện đến thời kỳ mấu chốt, yêu cầu giữ thân xử nữ, là lý do nàng xin ước hẹn ba mươi năm.","detail":"Mộ Phái Linh cho biết công pháp nàng đang tu luyện cần thân thể xử nữ, vô cùng trọng yếu cho bước đột phá sắp tới. Nàng lấy đó làm điều kiện xin Hàn Lập ba mươi năm không chiếm nguyên âm.","yeuCau":"Thân thể xử nữ","congNang":["Yêu cầu giữ thân xử nữ trong quá trình tu luyện đến thời kỳ mấu chốt"],"nguoiTu":[{"ten":"Mộ Phái Linh","tuChuong":"@c0641","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0641","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Mộ Phái Linh tiết lộ công pháp cần thân xử nữ","text":"Mộ Phái Linh nói công pháp nàng đang tu luyện đến thời kỳ mấu chốt, thân thể xử nữ vô cùng trọng yếu, xin ba mươi năm giữ nguyên âm.","anchor":"Mà công pháp này, thân thể xử nữ vô cùng trọng yếu"}]},"nguon":["@c0641"]},{"id":"dan-long-quyet","name":"Dẫn Long quyết","cn":"引龙诀","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Lục đạo cực thánh","Lục đạo thiếu chủ"],"blurb":"Bí thuật song tu ma đạo do Lục đạo cực thánh sáng tạo, thích hợp tu sĩ Kết Đan, cho nam tu hấp thu âm nguyên tinh của nữ nhân để tăng tu vi nhanh nhưng tổn hại nguyên khí nữ nhân.","detail":"Dẫn Long quyết là một trong hai môn song tu bí thuật ghi trong ngọc giản màu hồng mà Hàn Lập lấy được từ túi trữ vật của Lục đạo thiếu chủ. Dành cho tu sĩ Kết Đan Kỳ, cho phép nam tu hấp thu âm nguyên tinh của nữ nhân để tăng tu vi rất nhanh, nhưng đổi lại gây tổn hại lớn cho nguyên khí nữ nhân. Hàn Lập suy đoán Lục đạo thiếu chủ đạt Kết Đan Hậu Kỳ khi còn trẻ và có nhiều nữ tu Trúc Cơ bên cạnh là nhờ tu luyện bí thuật này.","nguonGoc":"Do Lục đạo cực thánh sáng tạo","congNang":["Cho nam tu Kết Đan hấp thu âm nguyên tinh của nữ nhân để tăng tu vi"],"dacDiem":"Tổn hại lớn nguyên khí nữ nhân bị hấp thu","nguoiTu":[{"ten":"Lục đạo thiếu chủ","tuChuong":"@c0642","tangDatToi":"","trangThai":"da-tu-huyen"}],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Được Hàn Lập phát hiện trong ngọc giản","text":"Hàn Lập lấy ngọc giản màu hồng từ túi trữ vật Lục đạo thiếu chủ, bên trong ghi Dẫn Long quyết thích hợp tu sĩ Kết Đan, suy đoán Lục đạo thiếu chủ đã dùng bí thuật này.","anchor":"một loại là Dẫn Long quyết thích hợp với tu sĩ Kết Đan Kỳ"}]},"nguon":["@c0642"]},{"id":"dien-phuong-boi-nguyen-cong","name":"Điên Phượng Bồi Nguyên công","cn":"颠凤培元功","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Bí thuật song tu ma đạo do Lục đạo cực thánh sáng tạo, dành cho tu sĩ Nguyên Anh, yêu cầu nữ tu Kết Đan kiêm tu rồi nam tu đoạt nguyên âm để hỗ trợ đột phá.","detail":"Điên Phượng Bồi Nguyên công là bí thuật song tu ma đạo ghi trong ngọc giản màu hồng, trái ngược với Dẫn Long quyết. Yêu cầu nữ tu phải đạt Kết Đan rồi kiêm tu bí thuật này, sau đó nam tu ở cảnh giới Nguyên Anh đoạt nguyên âm của nữ tu để mạnh mẽ đột phá tu vi. Hàn Lập coi đây là phương pháp dài hạn, định chờ Mộ Phái Linh kết đan xong mới cho nàng kiêm tu, nhằm thử một lần hỗ trợ đột phá sau Nguyên Anh.","nguonGoc":"Do Lục đạo cực thánh sáng tạo","congNang":["Hỗ trợ nam tu Nguyên Anh đoạt nguyên âm từ nữ tu Kết Đan kiêm tu để đột phá tu vi"],"dacDiem":"Yêu cầu nữ tu phải đạt Kết Đan rồi kiêm tu trước khi nam tu đoạt nguyên âm","nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hàn Lập phát hiện và lên kế hoạch dài hạn","text":"Hàn Lập tìm thấy trong ngọc giản và quyết định đây là lý do chính thu Mộ Phái Linh làm thiếp, chờ nàng kết đan rồi kiêm tu nhằm thử phương pháp đột phá sau Nguyên Anh.","anchor":"Mà bí thuật còn lại chính là Điên Phượng Bồi Nguyên công"}]},"nguon":["@c0642"]},{"id":"ngoc-gian-mau-hong","name":"Ngọc giản màu hồng","cn":"","loai":"khac","loaiLabel":"Ngọc giản công pháp","phamCap":"","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Ngọc giản lấy từ túi trữ vật Lục đạo thiếu chủ, ghi nhiều loại công pháp song tu ma đạo, nổi bật là Dẫn Long quyết và Điên Phượng Bồi Nguyên công.","detail":"Hàn Lập lấy ra từ túi trữ vật của Lục đạo thiếu chủ, bên trong ghi lại nhiều loại công pháp song tu ma đạo. Hai bí thuật quan trọng nhất là Dẫn Long quyết dành cho tu sĩ Kết Đan và Điên Phượng Bồi Nguyên công dành cho tu sĩ Nguyên Anh.","nguon":["@c0642"]},{"id":"dai-canh-kiem-tran","name":"Đại Canh Kiếm Trận","cn":"大庚剑阵","loai":"than-thong","loaiLabel":"Kiếm trận / Trận pháp","phamCap":"Cực phẩm (tầng 13 cuối cùng của Thanh Nguyên Kiếm Quyết)","hePhai":"Kiếm tu","soHuu":["Hàn Lập"],"blurb":"Thần thông tối cường ẩn ở tầng cuối Thanh Nguyên Kiếm Quyết, bị cấm chế theo cảnh giới; tu đến đỉnh chỉ 1/3 uy lực đã tung hoành Thiên Nam.","detail":"Kiếm trận liên quan trận pháp, là tầng 13 — tầng cuối cùng của Thanh Nguyên Kiếm Quyết. Khẩu quyết bị người luyện chế giấy vàng khóa bằng cấm chế theo cảnh giới, cần đạt Nguyên Anh Kỳ mới giải mở được. Tu luyện đến đỉnh thì chỉ cần 1/3 uy lực cũng có thể tung hoành Thiên Nam. Điều kiện bày trận: cần ít nhất trăm đạo kiếm quang, buộc phải luyện chế Thanh Trúc Phong Vân kiếm và trộn thêm tài liệu Canh Tinh vào mỗi phi kiếm. Hàn Lập tính dùng 72 phi kiếm mỗi thanh huyễn hóa 4 kiếm quang thành 362 đạo, đủ sức giết tu sĩ Nguyên Anh Trung Kỳ thậm chí Hậu Kỳ.","thuocTinh":"Kiếm","nguonGoc":"Ẩn trong giấy vàng ghi Thanh Nguyên Kiếm Quyết, bị cấm chế theo cảnh giới","yeuCau":"Nguyên Anh Kỳ trở lên mới giải cấm chế; cần ≥72 phi kiếm Thanh Trúc Phong Vân + Canh Tinh","uyLuc":"Tu đến đỉnh chỉ 1/3 uy lực đã tung hoành Thiên Nam; 72 phi kiếm ×4 kiếm quang = 362 đạo đủ giết Nguyên Anh Trung-Hậu Kỳ","dacDiem":"Liên quan trận pháp, cần bày trận bằng phi kiếm; Kiếm Ảnh Phân Quang thuật vốn được sáng tạo để phục vụ kiếm trận này","congNang":["Bày kiếm trận sát địch bằng hàng trăm kiếm quang từ phi kiếm"],"cacTang":[{"ten":"Đại Canh Kiếm Trận","moTa":"Tầng 13, tầng cuối cùng, kiếm trận liên quan trận pháp","chuong":"@c0643"}],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0643","tangDatToi":"Vừa lĩnh ngộ, chưa thi triển","trangThai":"dang-hoc"}],"trangThai":"Đã lĩnh ngộ, chưa thể thi triển (thiếu Canh Tinh)","capNhatToi":"@c0643","tabs":{"tienTrinh":[{"chuong":"@c0643","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Khai mở và lĩnh ngộ","text":"Hàn Lập đạt Nguyên Anh Kỳ, phun thanh quang giải cấm chế trên giấy vàng, khai mở tầng 13 Thanh Nguyên Kiếm Quyết. Ngồi lĩnh ngộ 3 ngày 3 đêm, nắm được toàn bộ kiếm trận nhưng chưa thể thi triển vì thiếu 72 phần Canh Tinh.","anchor":"Tu luyện đến đỉnh thì dù chỉ là một phần ba uy lực cũng có thể tung hoành Thiên Nam"}]},"nguon":["@c0643"]},{"id":"kiem-anh-phan-quang-thuat","name":"Kiếm Ảnh Phân Quang thuật","cn":"剑影分光术","loai":"than-thong","loaiLabel":"Kiếm thần thông","phamCap":"Tầng 3 của Thanh Nguyên Kiếm Quyết","hePhai":"Kiếm tu","soHuu":["Hàn Lập"],"blurb":"Tầng thứ ba của Thanh Nguyên Kiếm Quyết, phân hóa hàng trăm kiếm quang khiến đối thủ ngang tu vi không thể chống đỡ.","detail":"Thần thông kiếm tu thuộc tầng thứ ba của Thanh Nguyên Kiếm Quyết. Đối thủ ngang tu vi căn bản không thể chống đỡ mấy trăm kiếm quang công tới. Nay lộ ra Kiếm Ảnh Phân Quang vốn được sáng tạo để phục vụ việc bày Đại Canh Kiếm Trận ở tầng 13.","thuocTinh":"Kiếm","nguonGoc":"Được sáng tạo để phục vụ bày Đại Canh Kiếm Trận","uyLuc":"Phân hóa hàng trăm kiếm quang, đối thủ ngang tu vi không thể chống đỡ","congNang":["Phân hóa kiếm quang thành hàng trăm đạo tấn công đồng loạt"],"trangThai":"Đã tu luyện thành","capNhatToi":"@c0643","tabs":{"tienTrinh":[{"chuong":"@c0643","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Lộ nguồn gốc","text":"Lộ ra Kiếm Ảnh Phân Quang thuật vốn được sáng tạo để phục vụ việc bày Đại Canh Kiếm Trận, không phải thần thông độc lập.","anchor":"căn bản không thể chống đỡ mấy trăm kiếm quang công tới"}]},"nguon":["@c0643"]},{"id":"kinh-hon-thuat","name":"Kinh hồn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật Hàn Lập tu luyện, cho phép qua tiếp xúc hoặc thi triển lên người khác mà nhận ra đối phương có linh căn hay không cùng tư chất tu luyện.","detail":"Hàn Lập thi triển lên tiểu nhị A Nhị, chỉ qua tiếp xúc đã nhận ra A Nhị có linh căn tư chất đủ tu tới luyện khí kỳ tầng ba bốn. Hàn tự nhận đây là một loại bí thuật, khiến hai tu sĩ đồng hành kinh ngạc gọi là thần thông kinh người.","congNang":["Thăm dò linh căn và tư chất tu luyện của đối phương qua tiếp xúc"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0645","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0645","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập dùng Kinh hồn thuật lên tiểu nhị A Nhị tại khách điếm Vĩnh Khúc, phát hiện A Nhị có linh căn tư chất đủ tu tới luyện khí kỳ tầng ba bốn.","anchor":"vì sao với con người lại dùng Kinh hồn thuật"}]},"nguon":["@c0645"]},{"id":"tran-phap-vay-dich-tieu-coc","name":"Trận pháp vây địch trong tiểu cốc","loai":"bi-thuat","loaiLabel":"Trận pháp","soHuu":["Tu sĩ ục ịch họ La","Đại hán đầu hói"],"blurb":"Trận pháp đơn giản do Bành Dịch Song Hung bố trí sẵn trong tiểu cốc, dùng làm bẫy vây địch để phục kích tu sĩ Trúc Cơ.","detail":"Một trận pháp vây địch đơn giản được bố trí trong tiểu cốc phía sau tiểu sơn vắng người. Dùng để lừa mục tiêu vào rồi đánh lén, nhưng Hàn Lập dễ dàng phát hiện bằng thần thức do dao động linh khí cấm chế quá yếu ớt.","congNang":["Vây khốn mục tiêu trong tiểu cốc để phục kích"],"nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"xuat-hien","importance":"normal","giaiDoan":"Bố trí tại tiểu cốc","text":"Bành Dịch Song Hung bố trí sẵn trận pháp vây địch trong tiểu cốc để phục kích Hàn Lập, nhưng bị hắn phát hiện bằng thần thức trước khi vào.","anchor":"không ngờ còn bố trí trong cốc một trận pháp vây địch đơn giản"}]}},{"id":"huyen-quang-hoa-vat-quyet","name":"Huyễn quang hóa vật quyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lục sắc tiểu nhân"],"blurb":"Pháp quyết ẩn nặc hóa thân thành vật thể (cây nhỏ), khiến thần thức tu sĩ Nguyên Anh kỳ không phát hiện được.","detail":"Lục sắc tiểu nhân dùng pháp quyết này hóa thành một cây nhỏ để tránh thần thức dò xét. Chính nó tuyên bố pháp quyết này không có khả năng bị tu sĩ Nguyên Anh kỳ hiểu được, nhưng bị Minh Thanh Linh Nhãn của Hàn Lập phát hiện sai biệt.","congNang":["Ẩn nặc hóa thân thành vật thể (cây nhỏ), tránh thần thức dò xét"],"nguoiTu":[{"ten":"Lục sắc tiểu nhân","tuChuong":"@c0647","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phá giải","text":"Lục sắc tiểu nhân ẩn thân bằng pháp quyết này hóa thành cây nhỏ, nhưng bị Hàn Lập dùng Minh Thanh Linh Nhãn phát hiện sai biệt, buộc phải hiện hình.","anchor":"Huyễn quang hóa vật quyết này của ta không có khả năng bị tu sĩ Nguyên Anh Kỳ hiểu được"}]},"nguon":["@c0647"]},{"id":"minh-thanh-linh-nhan","name":"Minh Thanh Linh Nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thần thông linh nhãn giúp nhìn thấu ngụy trang ẩn nặc mà thần thức thông thường không phát hiện được.","detail":"Hàn Lập trong lúc cấp bách dùng thử Minh Thanh Linh Nhãn, nhờ lam quang phát ra mà phát hiện một cây nhỏ có sai biệt với xung quanh, từ đó ép lục sắc tiểu nhân đang dùng Huyễn quang hóa vật quyết phải hiện hình.","congNang":["Nhìn ra ngụy trang hóa vật mà thần thức không phát hiện được"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0647","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu sử dụng thực chiến","text":"Hàn Lập vô ý dùng thử, nhờ lam quang phát hiện cây nhỏ khác thường, ép lục sắc tiểu nhân hiện hình.","anchor":"trong lúc vô ý dùng thần thông Minh Thanh Linh Nhãn thử một lần"}]},"nguon":["@c0647"]},{"id":"kim-ho-dien-vong","name":"Kim hồ điện võng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông do Hàn Lập tự sáng chế, dùng Ích Tà Thần Lôi từ mười hai phi kiếm Kim Lôi Trúc kết thành lưới vàng co rút nhốt mục tiêu thành kim cầu, phong tỏa ngũ hành linh khí.","detail":"Hàn Lập ngưng hóa Ích Tà Thần Lôi thành điện võng bao chụp mục tiêu, co rút siết chặt thành kim cầu. Cần hơn mười đoạn Kim Lôi Trúc chứa Ích Tà Thần Lôi mới ngưng hóa được. Sau khi luyện thành Đại Diễn Quyết tầng thứ tư, thần thức mở rộng, Hàn Lập mới có thể thi triển trong đấu pháp với ít cố kỵ hơn trước.","congNang":["Giam cầm phong tỏa mục tiêu thành kim cầu","Phong tỏa ngũ hành linh khí khiến mục tiêu không thể thoát"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0648","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0648","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng trong thực chiến","text":"Hàn Lập dùng điện hồ từ mười hai phi kiếm kết thành lưới vàng chụp xuống Mộc Linh Anh, co rút nhốt thành kim cầu, lần đầu thi triển thần thông tự sáng chế trong đấu pháp thực tế.","anchor":"Ngưng hóa Ích Tà Thần Lôi thành lưới, loại thần thông này"}]},"nguon":["@c0648"]},{"id":"khoi-huong-phan-hong","name":"Khói hương phấn hồng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngân Nguyệt"],"blurb":"Ngân Nguyệt phun khói hương phấn hồng từ môi, làm đối phương hôn mê bất tỉnh dù có quang hoa hộ thể, hiệu quả tức thì xuyên qua phòng hộ.","detail":"Khói hương phấn hồng phun ra từ môi Ngân Nguyệt, xộc vào miệng mũi đối phương gây hôn mê tức thì. Quang hoa hộ thể của tu sĩ Kết Đan Kỳ hoàn toàn vô dụng trước chiêu này. Được sử dụng để hạ gục Phó Gia lão tổ trước khi chặt đầu.","thuocTinh":"Mị/Độc","nguonGoc":"","uyLuc":"Xuyên qua quang hoa hộ thể Kết Đan Kỳ, gây hôn mê tức thì","dacDiem":"Dạng khói hương phấn hồng phun từ môi","congNang":["Xộc vào miệng mũi gây hôn mê bất tỉnh","Vô hiệu hóa quang hoa hộ thể"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0651","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0651","loai":"thi triển","importance":"normal","giaiDoan":"Phục kích Phó Gia lão tổ","text":"Ngân Nguyệt phun khói hương phấn hồng từ môi làm Phó Gia lão tổ hôn mê bất tỉnh, quang hoa hộ thể hoàn toàn vô dụng.","anchor":"một mảnh khói hương phấn hồng trong nháy mắt phun ra, bao Phó Gia lão tổ đang không kịp đề phòng lại"}]},"nguon":["@c0651"]},{"id":"huyen-mau-hoa-anh-dai-phap","name":"Huyền Mẫu Hóa Anh Đại Pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cấp bậc gần ngang Nhất Khí Hóa Tam Thanh","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Bí công ma đạo ghi trong ngọc giản trận pháp thượng cổ thời hồng hoang, có thể bồi dưỡng nguyên thần thứ hai và thúc đẩy nguyên anh thứ hai đi ra.","detail":"Thần thông ma đạo cấp bậc gần ngang Nhất Khí Hóa Tam Thanh — đạo môn đệ nhất huyền công. Có thể bồi dưỡng nguyên thần thứ hai hàng thật giá thật, thậm chí thúc đẩy nguyên anh thứ hai đi ra. Ghi trong ngọc giản trận pháp thượng cổ thời hồng hoang (di vật Tân Như Âm). Ngân Nguyệt cảnh báo bí công ma đạo thường có tính chất tà môn, cần kiểm tra kỹ trước khi tu luyện.","nguonGoc":"Ghi trong ngọc giản trận pháp thượng cổ thời hồng hoang","thuocTinh":"Ma đạo","dacDiem":"Có thể có tính chất tà môn, cần nghiên cứu cẩn thận","congNang":["Bồi dưỡng nguyên thần thứ hai","Thúc đẩy nguyên anh thứ hai đi ra"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0654","tangDatToi":"Chưa bắt đầu tu luyện","trangThai":"nghien-cuu"}],"tabs":{"tienTrinh":[{"chuong":"@c0654","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện trong ngọc giản","text":"Hàn Lập tiết lộ cho Ngân Nguyệt bí công ma đạo ghi trong ngọc giản trận pháp thượng cổ, có thể bồi dưỡng nguyên thần thứ hai và thúc đẩy nguyên anh thứ hai đi ra, cấp bậc gần ngang Nhất Khí Hóa Tam Thanh. Quyết định nghiên cứu cẩn thận khi về Lạc Vân Tông.","anchor":"bí thuật bồi dưỡng nguyên thần thứ hai hàng thật giá thật, thậm chí có thể thúc dục nguyên anh thứ hai đi ra"}]},"capNhatToi":"@c0654","nguon":["@c0654"]},{"id":"dan-mong-thuat","name":"Dẫn Mộng Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Huyền Âm Kinh","soHuu":["Hàn Lập"],"blurb":"Bí công thuộc Huyền Âm Kinh, có thể phong ấn và cải biến trí nhớ người khác. Vượt xa Khống Thần Thuật và Vong Trần Đan.","detail":"Bí công nằm trong Huyền Âm Kinh, cho phép phong ấn trí nhớ liên quan và cải biến thành ký ức giả. Vượt xa Khống Thần Thuật và Vong Trần Đan. Chỉ người tu vi cao hơn xa mới có thể giải, nhưng chỉ dùng được khi chênh lệch tu vi rất lớn giữa người dùng và đối tượng, nếu không sẽ hao tổn thần thức người chịu thuật.","congNang":["Phong ấn trí nhớ liên quan","Cải biến trí nhớ thành ký ức giả"],"dacDiem":"Cần chênh lệch tu vi rất lớn, nếu không hao tổn thần thức người chịu thuật","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0654","tangDatToi":"Đã thi triển thành công","trangThai":"thanh-thuc"}],"tabs":{"tienTrinh":[{"chuong":"@c0654","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Hàn Lập thi triển Dẫn Mộng Thuật phong ấn trí nhớ phụ nhân Tề Vân Tiêu liên quan đến mình, cải biến thành ký ức gặp cao nhân ban đan dược.","anchor":"bắt đầu thi triển một loại bí công Dẫn mộng thuật Huyền Âm Kinh, phong ấn một ít trí nhớ liên quan lại"}]},"capNhatToi":"@c0654","nguon":["@c0654"]},{"id":"nhat-khi-hoa-tam-thanh","name":"Nhất Khí Hóa Tam Thanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đạo môn đệ nhất huyền công","hePhai":"Đạo môn","soHuu":[],"blurb":"Đạo môn đệ nhất huyền công, bí thuật nghịch thiên không dễ ngoại lưu. Được Hàn Lập nhắc đến như mốc so sánh cho Huyền Mẫu Hóa Anh Đại Pháp.","detail":"Đạo môn đệ nhất huyền công, bí thuật nghịch thiên. Được Hàn Lập nhắc đến khi tiết lộ về Huyền Mẫu Hóa Anh Đại Pháp, đánh giá bí công ma đạo kia có cấp bậc gần ngang với thần thông này.","nguon":["@c0654"]},{"id":"phap-thuat-thu-linh-tuyen","name":"Pháp thuật thu linh tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp thuật kết hợp dấu tay cổ quái và chú ngữ, thu gọn toàn bộ linh tuyền thành viên châu.","detail":"Hàn Lập thi triển dấu tay cổ quái kết hợp chú ngữ, hoàng quang bao phủ, khiến mặt nước bay lên, suối xoay tròn tạo hắc động, rồi thu gọn toàn bộ Linh Nhãn Chi Tuyền thành viên châu cỡ nắm tay.","congNang":["Thu gọn linh tuyền thành viên châu nhỏ gọn để mang đi"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0655","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0655","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Hàn Lập dùng pháp thuật thu gọn toàn bộ Linh Nhãn Chi Tuyền trong động phủ cũ tại Thái Nhạc Sơn Mạch thành viên châu cỡ nắm tay.","anchor":"hai tay kết xuất một cái dấu tay cổ quái, hai mắt nhìn chằm chằm linh tuyền, miệng lầm rầm đọc chú ngữ"}]},"nguon":["@c0655"]},{"id":"kiem-thuat-hop-kiem","name":"Kiếm thuật hợp kiếm (Thanh trúc phong vân kiếm)","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kỹ thuật hợp nhất nhiều thanh kiếm quang thành cự kiếm xanh hơn mười trượng, tốc độ cực nhanh, uy lực mạnh mẽ.","detail":"Hàn Lập phóng hơn mười thanh kiếm quang biến thành ba bốn mươi đạo chém giết nhóm tu sĩ, sau đó hợp thành cự kiếm xanh hơn mười trượng phóng đuổi theo tu sĩ áo xám, đánh tan mọi phòng thủ của đối phương.","congNang":["Kiếm quang nhân lên gấp nhiều lần, hợp thành cự kiếm tốc độ cực nhanh"],"tabs":{"tienTrinh":[{"chuong":"@c0656","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng diệt nhóm Quỷ Linh Môn","text":"Hàn Lập hợp hơn một trăm đạo kiếm quang thành cự kiếm xanh hơn mười trượng, tiêu diệt tu sĩ Kết Đan Kỳ Vu Hồng đang bỏ chạy cùng toàn bộ phòng thủ.","anchor":"hơn một trăm đạo kiếm quang liền tụ tập lại, trong nháy mắt tạo thành một thanh cự kiếm màu xanh thật lớn"}]},"nguon":["@c0656"]},{"id":"bi-cong-cam-ung-moc-linh-anh","name":"Bí công cảm ứng Mộc Linh Anh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Hạm Vân Chi","Liễu sư muội"],"blurb":"Công pháp do sư tổ Ngự Linh Tông tự mình truyền, cho phép đơn phương cảm ứng vị trí Mộc Linh Anh từ xa mấy trăm dặm mà đối phương dưới Nguyên Anh Hậu Kỳ không thể phát hiện.","detail":"Do sư tổ Ngự Linh Tông truyền cho Hạm Vân Chi và nữ tử họ Liễu. Chỉ cảm ứng đơn phương, không bị phát hiện trừ khi đối phương đạt Nguyên Anh Hậu Kỳ trở lên. Hàn Lập nhờ thần thức Đại Diễn Quyết tầng 4 cường đại hơn hẳn tu sĩ Nguyên Anh bình thường nên đã cảm nhận được.","thuocTinh":"Cảm ứng","nguonGoc":"Sư tổ Ngự Linh Tông truyền","congNang":["Đơn phương cảm ứng vị trí Mộc Linh Anh từ xa mấy trăm dặm"],"nguoiTu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0661","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Liễu sư muội","tuChuong":"@c0661","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0661","loai":"thi triển","importance":"normal","giaiDoan":"Nhóm Ngự Linh Tông dùng để truy tung Hàn Lập","text":"Hạm Vân Chi và nữ tử họ Liễu thi triển bí công cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập từ xa mấy trăm dặm, nhưng bị Hàn Lập phát hiện nhờ thần thức vượt trội.","anchor":"Công pháp của chúng ta là do sư tổ các ngươi tự mình truyền cho"}]},"nguon":["@c0661"]},{"id":"linh-hop-quyet","name":"Linh Hợp Quyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":[],"blurb":"Bí thuật liên kết pháp lực nhiều người thành một thể, đề cao tốc độ phi độn gần nửa.","detail":"Sáu người Ngự Linh Tông thi triển, liên kết pháp lực sáu người thành toàn thể tạo hoàng quang phi độn, tăng tốc độ gần nửa để chạy trốn khỏi Hàn Lập.","nguon":["@c0661"]},{"id":"phong-hoa-chi-don","name":"Phong hỏa chi độn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Phụ nhân họ Lâm"],"blurb":"Độn thuật cổ quái cực hiếm phối hợp phong và hỏa, biến cả người thành hỏa cầu to lớn kèm thanh quang, tốc độ ngang Nguyên Anh Sơ Kỳ dù người tu chỉ Kết Đan Sơ Kỳ. Đối địch yếu nhưng chạy cực nhanh.","detail":"Công pháp cổ quái mà phụ nhân họ Lâm (đệ tử Toái Hồn Chân Nhân) tu luyện. Khi thi triển, biến cả người thành hỏa cầu to lớn kèm thanh quang di chuyển cực nhanh. Khi phối hợp với pháp bảo phong thuộc tính Phiêu Linh Đái, tốc độ như hổ thêm cánh, đạt ngang Nguyên Anh Sơ Kỳ. Tuy nhiên khi đối địch thì so với công pháp đỉnh cấp khác thua kém không ít.","thuocTinh":"Phong, Hỏa","nguonGoc":"","dacDiem":"Chiến đấu yếu nhưng độn thuật cực mạnh, cực hiếm thấy","congNang":["Độn thuật phong+hỏa, tốc độ ngang Nguyên Anh Sơ Kỳ dù Kết Đan Sơ Kỳ"],"nguoiTu":[{"ten":"Phụ nhân họ Lâm","tuChuong":"@c0662","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0662","loai":"thi triển","importance":"normal","giaiDoan":"Phụ nhân họ Lâm thi triển đào tẩu","text":"Phụ nhân họ Lâm thi triển Phong hỏa chi độn kết hợp Phiêu Linh Đái, hóa hồng quang bỏ chạy xa nhất bốn năm mươi dặm, tốc độ ngang Nguyên Anh Sơ Kỳ.","anchor":"tại độn thuật lại là Phong hỏa chi độn cực hiếm thấy"}]},"nguon":["@c0662"]},{"id":"bi-thuat-tang-toc-linh-cam","name":"Bí thuật tăng tốc linh cầm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Hạm Vân Chi"],"blurb":"Bí thuật phun quang châu cố định lên đầu linh cầm kết hợp pháp quyết, tăng tốc độ gấp rưỡi nhưng cực hao nguyên khí.","detail":"Hạm Vân Chi phun ra viên quang châu trong suốt, cố định lên đầu linh cầm bạch điểu rồi kết pháp quyết. Tốc độ độn thuật tăng gấp rưỡi nhưng rất hao tổn nguyên khí, khiến sắc mặt trắng bệch.","congNang":["Tăng tốc linh cầm gấp rưỡi"],"dacDiem":"Cực hao nguyên khí","nguoiTu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0664","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"thi triển","importance":"normal","giaiDoan":"Hạm Vân Chi thi triển khi chạy trốn","text":"Hạm Vân Chi phun quang châu cố định lên đầu linh cầm, thi triển bí thuật tăng tốc gấp rưỡi nhưng cực hao nguyên khí, sắc mặt trắng bệch.","anchor":"một công pháp rất hao tổn nguyên khí"}]},"nguon":["@c0664"]},{"id":"cam-che-nhan-chu-tu-bao","name":"Cấm chế nhận chủ và cấm chế tự bạo","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Hai loại cấm chế mà tu sĩ sử dụng linh trùng hạ lên: cấm chế nhận chủ ràng buộc linh trùng với chủ nhân, cấm chế tự bạo khiến linh trùng tự hủy khi chủ chết.","detail":"Tu sĩ sử dụng linh trùng đều hạ hai cấm chế — nhận chủ (ràng buộc linh trùng) và tự bạo (linh trùng tự hủy khi chủ chết, nguyên thần tiêu tan). Chỉ khi chủ nhân tự giác loại bỏ cấm chế mới có thể truyền linh trùng cho người khác. Phệ Kim Trùng của Hàn Lập cũng đã được chủ cũ gỡ bỏ cấm chế này.","congNang":["Ràng buộc linh trùng với chủ nhân","Linh trùng tự hủy khi chủ chết, ngăn kẻ thù chiếm đoạt"],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Giải thích cơ chế cấm chế linh trùng","text":"Giải thích cơ chế cấm chế nhận chủ và tự bạo trên linh trùng, lý do Hàn Lập không thể giết nữ tu để chiếm Lục Dực Sương Công.","anchor":"hễ là tu sĩ sử dụng linh trùng, vì sợ sau khi bị bỏ mình ngoài ý muốn, linh vật liền bị cừu gia lấy được"}]},"nguon":["@c0664"]},{"id":"ngu-hanh-linh-anh","name":"Ngũ Hành Linh Anh","cn":"五行灵婴","aliases":["Dung hợp Linh Anh đại pháp"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đại bí thuật thần thông cổ","hePhai":"Ngự Linh Tông","soHuu":["Ngự Linh Tông"],"blurb":"Đại bí thuật thần thông thất truyền nhiều năm của Ngự Linh Tông. Dung hợp năm Linh Anh (Kim/Mộc/Thủy/Hỏa/Thổ) vào đệ tử, tạo tu sĩ có thần thông Nguyên Anh Kỳ nhưng không có thọ mệnh Nguyên Anh.","detail":"Bí pháp cổ của Ngự Linh Tông, thất truyền nhiều năm, được khôi phục khi lão giả vô ý luyện ra Thổ Linh Anh. Kế hoạch: chuẩn bị đủ năm Linh Anh → dung hợp vào đệ tử bổn môn → tạo năm tu sĩ có thần thông Nguyên Anh Kỳ, đủ sức tranh đua Hợp Hoan Tông vị trí đứng đầu ma đạo. Hạn chế: đệ tử hợp thể có thần thông Nguyên Anh nhưng không có thọ mệnh Nguyên Anh. Trước khi dung hợp phải làm suy yếu tu vi Linh Anh để bảo vệ nguyên thần đệ tử. Mộc Linh Anh nếu dung hợp thành công, đệ tử có thể đạt thần thông Nguyên Anh Trung Kỳ.","thuocTinh":"Ngũ Hành","nguonGoc":"Bí thuật cổ thất truyền của Ngự Linh Tông","yeuCau":"Phải có đủ năm Linh Anh, suy yếu tu vi Linh Anh trước khi dung hợp","uyLuc":"Tạo tu sĩ có thần thông ngang Nguyên Anh Kỳ","dacDiem":"Đệ tử hợp thể không có thọ mệnh Nguyên Anh; Mộc Linh Anh có thể cho thần thông Nguyên Anh Trung Kỳ","congNang":["Dung hợp Linh Anh vào đệ tử → đệ tử có thần thông Nguyên Anh Kỳ"],"trangThai":"Đang khôi phục, mất Mộc Linh Anh","capNhatToi":"@c0665","nguoiTu":[{"ten":"Ngự Linh Tông (toàn tông)","tuChuong":"@c0665","tangDatToi":"Chưa dung hợp","trangThai":"chuẩn bị"}],"tabs":{"tienTrinh":[{"chuong":"@c0665","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ bí mật toàn bộ kế hoạch","text":"Lão giả và trung niên nam tử tiết lộ bí pháp Ngũ Hành Linh Anh: đại bí thuật thất truyền, khôi phục nhờ luyện ra Thổ Linh Anh. Kế hoạch dung hợp năm Linh Anh vào đệ tử tạo năm tu sĩ thần thông Nguyên Anh Kỳ. Mộc Linh Anh đã bị mất, còn hai Linh Anh và một dự bị.","anchor":"Bí pháp Ngũ Hành Linh Anh này nguyên vốn là một đại bí thuật thần thông thất truyền nhiều năm"}]},"nguon":["@c0665"]},{"id":"suu-hon-thuat","name":"Sưu hồn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Lão giả thạch thất Kỳ Linh Sơn","Bạch sam lão giả"],"blurb":"Thủ pháp thương tổn thần thức độc địa, dùng để tra hỏi đối tượng bằng cách tổn thương thần thức.","detail":"Bí thuật tra hỏi bằng cách tổn thương thần thức đối tượng. Lão giả thạch thất nhắc đến khi cân nhắc tra hỏi Hạm Vân Chi nhưng không dùng vì nể mặt Hạm sư đệ.","congNang":["Tra hỏi đối tượng bằng cách tổn thương thần thức","Tìm kiếm, trích xuất ký ức trong thần hồn đối phương"],"nguon":["@c0665","@c0702"],"tabs":{"tienTrinh":[{"chuong":"@c0702","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến lần đầu","text":"Lão giả họ Vân đề xuất dùng Sưu hồn thuật lên Nam Lũng Hầu để trích xuất tin tức về Trụy Ma Cốc.","anchor":"để ta dùng Sưu hồn thuật, xem một chút coi có lấy được tin tức gì hữu dụng hay không"}]},"nguoiTu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0702","tangDatToi":"","trangThai":"dang-co"}]},{"id":"bi-thuat-cam-ung-trai-tim","name":"Bí thuật cảm ứng trái tim","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Trung niên nam tử mắt to mày rậm"],"blurb":"Bí thuật cảm ứng trạng thái tâm lý đối tượng, có thể phát hiện dối trá.","detail":"Trung niên nam tử dùng để kiểm tra Hạm Vân Chi khi nàng báo cáo, xác nhận nàng đại bộ phận nói thật nhưng đoạn chạy thoát có chút hỗn loạn, phỏng chừng giấu diếm.","congNang":["Cảm ứng trạng thái tâm lý đối tượng, phát hiện dối trá"],"nguon":["@c0665"]},{"id":"dung-hop-linh-anh-dai-phap","name":"Dung hợp Linh Anh đại pháp","cn":"","aliases":["Ngũ Hành Linh Anh"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Ngự Linh Tông"],"blurb":"Bí thuật cốt lõi của Ngự Linh Tông: dùng năm loại Linh Anh thuộc tính khác nhau thay thế Nguyên Anh, giúp tu sĩ Kết Đan trực tiếp đạt tu vi Nguyên Anh Kỳ. Khuyết điểm: thọ mệnh vẫn ở mức Kết Đan, vĩnh viễn mất cơ hội kết Nguyên Anh thật, tu vi đình trệ.","detail":"Bí thuật cổ của Ngự Linh Tông, cho phép tu sĩ Kết Đan dung hợp năm loại Linh Anh thuộc tính bất đồng (Kim, Mộc, Thủy, Hỏa, Thổ) để thay thế Nguyên Anh, từ đó có được tu vi cùng thần thông của Nguyên Anh Kỳ mà không cần tự ngưng kết Nguyên Anh. Điều kiện luyện chế Linh Anh cực khắt khe: tài liệu cực hiếm, cần trưởng lão sắp tọa hóa phối hợp (nguyên anh tán đi là điều kiện bắt buộc), xác suất thành công cực thấp (mười mấy lần may ra một lần). Ngự Linh Tông tích lũy đến nay chỉ có sáu bảy Linh Anh, đã tuyển mười tu sĩ Kết Đan làm ứng viên dung hợp. Khuyết điểm: sau dung hợp thọ mệnh chỉ ở mức Kết Đan Kỳ, vĩnh viễn mất cơ hội kết Nguyên Anh thật, tu vi đình trệ không tiến thêm — tương tự phương pháp tốc hành của tu sĩ Sát Đan.","thuocTinh":"Ngũ hành (cần đủ 5 thuộc tính)","nguonGoc":"Bí thuật cổ truyền của Ngự Linh Tông","yeuCau":"Tu sĩ Kết Đan tu luyện công pháp tương ứng thuộc tính; cần đủ 5 loại Linh Anh","uyLuc":"Trực tiếp đạt tu vi và thần thông Nguyên Anh Kỳ","dacDiem":"Thọ mệnh vẫn Kết Đan, mất cơ hội kết Nguyên Anh thật, tu vi đình trệ","congNang":["Dùng 5 Linh Anh thuộc tính khác nhau thay thế Nguyên Anh, tu sĩ Kết Đan đạt tu vi Nguyên Anh Kỳ @c0666"],"nguoiTu":[],"trangThai":"Ngự Linh Tông đang chuẩn bị tuyển ứng viên dung hợp","capNhatToi":"@c0666","tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Bí mật bị tiết lộ cho Hàn Lập","text":"Liễu Ngọc dưới áp lực thẩm vấn của Hàn Lập tiết lộ toàn bộ bí mật: Dung hợp Linh Anh đại pháp dùng 5 Linh Anh thay Nguyên Anh, giúp tu sĩ Kết Đan đạt tu vi Nguyên Anh Kỳ. Khuyết điểm: thọ mệnh vẫn Kết Đan, mất cơ hội kết Nguyên Anh thật.","anchor":"Không cần tự mình ngưng kết Nguyên Anh, liền có thể trực tiếp lấy Linh Anh thay thế Nguyên Anh, từ đó có được tu vi cùng thần thông của Nguyên Anh Kỳ"}]},"nguon":["@c0666"]},{"id":"bi-thuat-cam-ung-phuong-vi-moc-linh-anh","name":"Bí thuật cảm ứng phương vị Mộc Linh Anh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngự Linh Tông","soHuu":["Liễu Ngọc"],"blurb":"Bí thuật đặc thù của Ngự Linh Tông, cần hai người cùng tu luyện, có thể cảm ứng phương vị Mộc Linh Anh từ xa, giới hạn ngoài mười mấy vạn dặm thì vô hiệu.","detail":"Bí thuật cảm ứng do Ngự Linh Tông truyền dạy, yêu cầu hai tu sĩ cùng tu luyện phối hợp mới có thể đại khái cảm ứng phương vị của Mộc Linh Anh từ cự ly xa. Khoảng cách hữu hiệu giới hạn trong mười mấy vạn dặm, vượt quá thì không thể cảm ứng. Liễu Ngọc và đồng môn sư tỷ là hai người đã tu luyện bí thuật này.","thuocTinh":"Cảm ứng","nguonGoc":"Ngự Linh Tông","yeuCau":"Hai người cùng tu luyện phối hợp","dacDiem":"Giới hạn mười mấy vạn dặm","congNang":["Cảm ứng phương vị Mộc Linh Anh từ cự ly xa, cần 2 người phối hợp @c0666"],"nguoiTu":[{"ten":"Liễu Ngọc","tuChuong":"@c0666","tangDatToi":"","trangThai":"dang-tu"}],"trangThai":"Đang sử dụng","capNhatToi":"@c0666","tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Liễu Ngọc tiết lộ cho Hàn Lập","text":"Liễu Ngọc khai báo phương thức truy tìm: nàng cùng đồng môn sư tỷ tu luyện bí thuật cảm ứng phương vị Mộc Linh Anh từ xa, giới hạn mười mấy vạn dặm.","anchor":"cùng với một vị đồng môn sư tỷ khác tu luyện một loại bí thuật đặc thù, có thể đại khái cảm ứng được phương vị của Mộc Linh Anh từ cự ly xa"}]},"nguon":["@c0666"]},{"id":"tu-la-thanh-hoa","name":"Tu La Thánh Hỏa","cn":"修罗圣火","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Huyền Cốt"],"blurb":"Hỏa thuật từng do Huyền Cốt lão ma thi triển, được Hàn Lập nhắc đến sau khi dung hợp sương hoa và lam diễm thành chim lửa tím.","detail":"Hàn Lập liên hệ đến Tu La Thánh Hỏa ngay sau khi trình diễn dung hợp sương hoa trắng với băng diễm xanh biếc, cho thấy hắn đang nghiên cứu hỏa thuật có liên quan đến loại thần thông này.","nguoiTu":[{"ten":"Huyền Cốt","tuChuong":"@c0667","tangDatToi":"Chưa rõ","trangThai":"da-thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c0667","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập nhắc đến sau dung hợp sương hoa lam diễm","text":"Hàn Lập hỏi Ngân Nguyệt có nhớ Huyền Cốt lão ma thi triển Tu La Thánh Hỏa không, ngay sau khi trình diễn dung hợp sương hoa và lam diễm thành chim lửa tím.","anchor":"Huyền Cốt lão ma thi triển Tu La Thánh Hỏa lúc đầu không"}]},"nguon":["@c0667"]},{"id":"trung-giap-thuat","name":"Trùng Giáp Thuật","cn":"虫甲术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Bí thuật phòng ngự phái sinh từ Khu Trùng Thuật của Ngự Linh Tông, dùng Phệ Kim Trùng ngưng tụ thành bảo giáp chiến giáp trên thân người, cực kỳ chắc chắn.","detail":"Hàn Lập học từ ngọc giản Khu Trùng Thuật do Liễu Mi cung cấp, kết hợp nghiên cứu Huyền Mẫu Hóa Anh Đại Pháp, luyện thành công. Triệu hồi mấy ngàn con tam sắc Phệ Kim Trùng, phóng khói xanh bao trùm, dùng pháp ấn điều khiển đám trùng tụ lại trên thân, ngưng tụ thành bảo giáp chiến giáp hoa văn ba màu — thanh quang lóng lánh, bóng loáng, nhìn không ra dị thường. Ngự Linh Tông đã sớm nghiên cứu ra phương pháp này.","thuocTinh":"Không rõ","nguonGoc":"Khu Trùng Thuật của Ngự Linh Tông","congNang":["Ngưng tụ Phệ Kim Trùng thành bảo giáp phòng ngự trên thân, hoa văn ba màu, cực kỳ chắc chắn"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0668","tangDatToi":"Thành công lần đầu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập luyện thành công lần đầu","text":"Hàn Lập nghiên cứu Khu Trùng Thuật cùng Huyền Mẫu Hóa Anh Đại Pháp, triệu hồi mấy ngàn con tam sắc Phệ Kim Trùng, dùng pháp ấn ngưng tụ thành bảo giáp chiến giáp ba màu trên thân, thanh quang lóng lánh cực kỳ chắc chắn.","anchor":"Trước kia tại Hư Thiên Điện thật không nghĩ tới dùng Phệ Kim Trùng ngưng tụ thành một bảo giáp"}]},"nguon":["@c0668"]},{"id":"khu-trung-thuat","name":"Khu trùng thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật ghi lại nhiều phương pháp điều động trùng tấn công, Hàn Lập tu luyện xong dễ dàng nhờ tu vi Nguyên Anh kỳ.","detail":"Bí thuật chứa các phương pháp điều động trùng tấn công. Với tu vi Nguyên Anh kỳ, Hàn Lập dễ dàng nắm bắt. Trong đó có chứa pháp quyết Trùng Giáp Thuật cho phép ngưng kết trùng thành chiến giáp hộ thể.","congNang":["Điều động trùng tấn công theo nhiều phương pháp"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0669","tangDatToi":"","trangThai":"đại thành"}],"tabs":{"tienTrinh":[{"chuong":"@c0669","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tu luyện xong","text":"Hàn Lập tu luyện xong Khu trùng thuật dễ dàng nhờ tu vi Nguyên Anh, nắm được các phương pháp điều động trùng tấn công.","anchor":"Trên đó có ghi lại vài phương pháp điều động trùng tấn công làm cho hắn hài lòng không thôi"}]},"nguon":["@c0669"]},{"id":"quy-nhat-quyet","name":"Quy Nhất Quyết","cn":"归一诀","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Ma đạo","soHuu":[],"blurb":"Bí thuật phụ trong Huyền Mẫu Hóa Anh Đại Pháp, dùng đánh tan tâm ma, đồng hóa hai nguyên thần, ngăn hóa thân phản khách vi chủ.","detail":"Bí thuật nằm trong Huyền Mẫu Hóa Anh Đại Pháp. Tác dụng: đánh tan tâm ma, đồng hóa hai nguyên thần (chủ thể và hóa thân), tăng mạnh khống chế của chủ thể đối với hóa thân. Cần sử dụng định kỳ để ngăn hóa thân dần khác biệt trí nhớ, tình cảm dẫn tới hóa ma và cắn trả.","congNang":["Đánh tan tâm ma, đồng hóa hai nguyên thần","Tăng mạnh khống chế chủ thể đối với hóa thân","Ngăn hóa thân phản khách vi chủ"],"tabs":{"tienTrinh":[{"chuong":"@c0669","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong công pháp","text":"Hàn Lập phát hiện bí thuật Quy Nhất Quyết trong Huyền Mẫu Hóa Anh Đại Pháp, dùng định kỳ để đồng hóa hai nguyên thần chống hóa ma.","anchor":"Cách một đoạn thời gian sẽ dùng bí thuật “Quy Nhất Quyết” trong Huyền Mẫu Hóa Anh Đại Pháp đánh tan tâm ma"}]},"nguon":["@c0669"]},{"id":"thuong-nguyen-diet-quang-tran","name":"Thượng Nguyên Diệt Quang trận","cn":"上元灭光阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Liên minh chín nước","soHuu":["Liên minh chín nước"],"blurb":"Địa trận do liên minh chín nước mở ra trước khi khai đàn Giao dịch hội, đại bộ phận cấm chế đã triệu hồi, dùng bảo vệ khu vực tổ chức.","detail":"Liên minh chín nước mở địa trận này một hai tháng trước khi Giao dịch hội khai đàn. Đại bộ phận cấm chế trong trận đã được triệu hồi, có tác dụng bảo vệ toàn bộ khu vực thành tu sĩ nơi tổ chức Giao dịch hội.","congNang":["Bảo vệ khu vực Giao dịch hội tại tổng đàn liên minh chín nước","Phòng thủ thành trì, tạo linh quang bao phủ bầu trời ngăn chặn xâm nhập"],"tabs":{"tienTrinh":[{"chuong":"@c0670","loai":"xuất hiện","importance":"normal","giaiDoan":"Được kích hoạt trước Giao dịch hội","text":"Liên minh chín nước mở Thượng Nguyên Diệt Quang trận trước khi khai đàn, đại bộ phận cấm chế đã triệu hồi.","anchor":"liên minh chín nước đã mở ra một địa trận, là “Thượng Nguyên Diệt Quang trận”"},{"chuong":"@c0718","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt phòng thủ","text":"Điền Thiên Thành triệt hồi cấm chế trên không trung nhưng mở đại bộ phận Thượng Nguyên Diệt Quang Trận, bầu trời tràn ngập linh quang quỷ dị, đánh dấu trạng thái chiến tranh.","anchor":"mở ra đại bộ phận “Thượng Nguyên Diệt Quang Trận”"}]},"nguon":["@c0670","@c0718"]},{"id":"ngan-lang-quyet","name":"Ngân Lăng Quyết","cn":"银棱诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Thủy","soHuu":["Lữ Lạc"],"blurb":"Công pháp hệ thủy của Lữ Lạc, khắc chế Kết Đan Kỳ dễ dàng nhưng đấu đồng cấp Nguyên Anh bại nhiều hơn thắng. Có hai loại bảo hộ tính mạng, nhiều lần cứu mạng chủ nhân.","detail":"Ngân Lăng Quyết là công pháp hệ thủy, Lữ Lạc khiêm tốn gọi là bình thường. Đối phó Kết Đan Kỳ thì dễ dàng, nhưng đấu với đồng cấp Nguyên Anh Kỳ thì bại nhiều hơn thắng. Đặc biệt có hai loại bảo hộ tính mạng, nhiều lần cứu Lữ Lạc thoát chết — từng bị chính tà vây khốn mà chạy về Vân Mộng Sơn không chút tổn hại.","thuocTinh":"Thủy","uyLuc":"Khắc chế Kết Đan Kỳ, yếu thế trước đồng cấp Nguyên Anh Kỳ","dacDiem":"Có hai loại bảo hộ tính mạng đặc biệt","congNang":["Chiến đấu hệ thủy","Bảo hộ tính mạng (hai loại, chi tiết chưa rõ)"],"nguoiTu":[{"ten":"Lữ Lạc","tuChuong":"@c0671","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0671","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lữ Lạc tiết lộ đặc tính","text":"Lữ Lạc khiêm tốn nói Ngân Lăng Quyết chỉ là công pháp hệ thủy bình thường, tiết lộ có hai loại bảo hộ tính mạng cứu mạng nhiều lần.","anchor":"Ngân Lăng Quyết này chỉ là công pháp hệ thủy bình thường mà thôi"}]},"capNhatToi":"@c0671","nguon":["@c0671"]},{"id":"than-thuc-hoa-hinh","name":"Thần thức hóa hình","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu cầu lý thuyết Nguyên Anh Trung Kỳ","hePhai":"","soHuu":["Hàn Lập","Nam Lũng Hầu"],"blurb":"Thần thông cô đọng thần thức thành hình thể hữu hình để tỷ đấu, lý thuyết chỉ tu sĩ Nguyên Anh Trung Kỳ với thần thức cường đại mới nắm giữ được.","detail":"Thần thức hóa hình cho phép tu sĩ cô đọng thần thức thành bóng đen nhìn thấy được, dùng để tỷ đấu thần thức. Theo lý thuyết, chỉ tu sĩ Nguyên Anh Trung Kỳ trở lên với thần thức cường đại mới có thể nắm giữ thần thông này. Hàn Lập ở Nguyên Anh Sơ Kỳ đã thi triển được, khiến Lữ Lạc kinh ngạc và suy đoán công pháp chủ tu của Hàn Lập thiên về hướng thần thức.","thuocTinh":"Thần thức","nguonGoc":"","yeuCau":"Thần thức cường đại, lý thuyết Nguyên Anh Trung Kỳ","uyLuc":"Cô đọng thần thức thành hình bóng hữu hình, va chạm tạo cuồng phong dữ dội, quét bốn phương","dacDiem":"Bóng đen hữu hình, hai luồng thần thức va chạm tạo gió lốc và sét đánh","congNang":["Cô đọng thần thức thành hình thể hữu hình để tỷ đấu thần thức"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0673","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Nam Lũng Hầu","tuChuong":"@c0673","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0673","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập và Nam Lũng Hầu thi triển thần thức hóa hình trong trận tỷ thí, hai luồng thần thức cô đọng thành hình va chạm tạo cuồng phong dữ dội. Lữ Lạc xác nhận đây là thần thông Nguyên Anh Trung Kỳ, Hàn Lập Sơ Kỳ thi triển được là dị thường.","anchor":"Thần thức hóa hình là thần thông do tu sĩ Nguyên Anh Trung Kỳ bằng vào thần thức cường đại mới có thể nắm giữ"}]},"capNhatToi":"@c0673","dinhDanh":"goc","nguon":["@c0673"]},{"id":"song-tu-bi-thuat-hop-hoan-tong","name":"Song tu bí thuật (Hợp Hoan Tông)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma Môn Hợp Hoan Tông","soHuu":["Tu sĩ mập mạp (Phì Xá song ma — nam)","Nữ tu phong mãn (Phì Xá song ma — nữ)"],"blurb":"Bí thuật song tu của Phì Xá song ma thuộc Hợp Hoan Tông, cho phép hai người liên thủ chống lại tu sĩ Nguyên Anh Trung Kỳ dù bản thân chỉ ở Nguyên Anh Sơ Kỳ.","detail":"Bí thuật song tu đặc thù của Ma Môn Hợp Hoan Tông. Phì Xá song ma thông qua bí thuật này liên thủ, chiến lực vượt cấp, thậm chí có thể cùng chống lại tu sĩ Nguyên Anh Trung Kỳ.","congNang":["Liên thủ hai người tăng chiến lực vượt cấp, đối kháng Nguyên Anh Trung Kỳ"],"nguoiTu":[{"ten":"Tu sĩ mập mạp (Phì Xá song ma — nam)","tuChuong":"@c0675","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Nữ tu phong mãn (Phì Xá song ma — nữ)","tuChuong":"@c0675","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0675","loai":"nhắc tới","importance":"normal","giaiDoan":"Lữ Lạc cảnh báo Hàn Lập","text":"Lữ Lạc truyền âm cảnh báo Hàn Lập về Phì Xá song ma, cho biết hai người thông qua song tu bí thuật liên thủ có thể chống lại tu sĩ Nguyên Anh Trung Kỳ.","anchor":"Phì Xá song ma. Hai người này thông qua song tu bí thuật liên thủ, thậm chí có thể cùng chống lại tu sĩ Nguyên Anh Trung Kỳ"}]},"nguon":["@c0675"]},{"id":"tinh-quang-cong","name":"Tinh quang công","cn":"星光功","loai":"cong-phap","loaiLabel":"Công pháp","soHuu":["Thiên Tinh Chân Nhân"],"blurb":"Công pháp chính mà Thiên Tinh Chân Nhân tu luyện, được Lão Cúc Hợp Hoan Tông nhắc đến khi hỏi đùa về chuyện cải tu Khôi Lỗi Thuật.","detail":"Công pháp tu luyện của Thiên Tinh Chân Nhân. Lão Cúc hỏi đùa liệu Thiên Tinh Chân Nhân có buông bỏ Tinh quang công để cải tu Khôi Lỗi Thuật không, cho thấy đây là công pháp gốc mà lão tu luyện từ đầu.","nguoiTu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0677","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0677","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tại trao đổi hội","text":"Lão Cúc Hợp Hoan Tông hỏi đùa Thiên Tinh Chân Nhân có buông bỏ Tinh quang công để cải tu Khôi Lỗi Thuật không, xác nhận đây là công pháp chính của lão.","anchor":"Chẳng lẽ Tinh quang công mà lúc đầu tu luyện định buông tha sao"}]},"nguon":["@c0677"]},{"id":"che-phu-thuat","name":"Chế phù thuật","cn":"制符术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không cố định (tùy cấp bậc chế phù sư)","hePhai":"Không giới hạn","soHuu":[],"blurb":"Kỹ năng luyện chế phù lục, cần bút chế phù chuyên dụng và nguyên liệu tương ứng; chế phù sư Kết Đan kỳ cực hiếm, Nguyên Anh kỳ chuyên chế phù thì không có.","detail":"Hệ thống kỹ năng luyện chế phù lục trong tu tiên giới. Chế phù sư phần lớn chỉ ở Trúc Cơ kỳ; tại Thiên Nam, chế phù sư đạt Kết Đan kỳ cả tu tiên giới cũng chỉ có mấy người, còn Nguyên Anh kỳ chuyên chế phù thì hoàn toàn không tồn tại. Tu sĩ Nguyên Anh chỉ kiêm tu một hai loại phù hữu dụng cho bản thân. Chế phù cần bút chế phù chuyên dụng chứa linh khí đặc thù; nếu pháp lực không đủ mà dùng bút cao cấp sẽ tăng tỷ lệ thất bại. Phù lục cao cấp do Kết Đan kỳ chế tạo, so với đỉnh cấp pháp khí tại tu tiên giới có khi còn quý hơn ba phần.","nguon":["@c0678"]},{"id":"ngu-hanh-phap-thuat-cao-cap","name":"Ngũ hành pháp thuật cao cấp","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Cao cấp (trên pháp thuật thường)","hePhai":"Ngũ hành","soHuu":["Hàn Lập"],"blurb":"Nhóm pháp thuật ngũ hành cao cấp, uy lực cường đại đến mức tu sĩ Nguyên Anh Kỳ cũng kiêng dè, nhưng tu luyện và thi triển vô cùng phiền phức.","detail":"Tu sĩ Kết Đan trở lên hầu hết bỏ tu vì uy lực không bằng pháp bảo khi thi triển, thời gian quá lâu. Hàn Lập sau khi ngưng tụ Nguyên Anh đã lĩnh ngộ ba bốn loại nhưng tốc độ thi triển quá chậm, không dùng được trong đấu pháp. Nếu phối hợp phù lục cao cấp (ném hai ba mươi cùng lúc) thì tương đương mười mấy Nguyên Anh tấn công, nhưng mỗi lần hao mấy vạn linh thạch.","congNang":["Công kích ngũ hành cao cấp, một số đủ khiến tu sĩ Nguyên Anh Kỳ kiêng dè"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0679","tangDatToi":"Đã lĩnh ngộ 3-4 loại, thi triển quá chậm","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Hàn Lập suy tư về hạn chế","text":"Hàn Lập sau khi ngưng tụ Nguyên Anh lĩnh ngộ ba bốn loại pháp thuật cao cấp nhưng tốc độ thi triển quá chậm, không thể dùng trong đấu pháp. Nhận định đại bộ phận tu sĩ Kết Đan bỏ tu pháp thuật vì uy lực không bằng pháp bảo.","anchor":"uy lực của đại bộ phận pháp thuật cao cấp, còn không bằng uy lực cường đại của việc sử dụng pháp bảo"}]},"nguon":["@c0679"]},{"id":"phap-thuat-tuc-thi-mac-lan","name":"Pháp thuật tức thì của pháp sĩ Mạc Lan","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật đặc thù","phamCap":"Cực cao","hePhai":"","soHuu":["Mạc Lan"],"blurb":"Thành quả nghiên cứu đột phá của pháp sĩ Mạc Lan, cho phép thi triển pháp thuật nháy mắt với đại uy lực, khiến liên minh các thế lực Thiên Nam cũng chỉ tự bảo vệ.","detail":"Mạc Lan đột phá cực hạn pháp thuật, nghiên cứu ra cách thi triển tức thì đại uy lực. Pháp sĩ cấp thấp không cần pháp khí cũng đánh ngang tu sĩ thường, pháp sĩ cao cấp phối hợp pháp bảo như hổ thêm cánh.","congNang":["Thi triển pháp thuật nháy mắt với đại uy lực","Pháp sĩ cấp thấp không cần pháp khí đánh ngang tu sĩ thường"],"nguoiTu":[{"ten":"Mạc Lan","tuChuong":"@c0679","tangDatToi":"Đột phá cực hạn","trangThai":"thanh-cong"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Hàn Lập nhớ lại thành tựu Mạc Lan","text":"Hàn Lập nhớ lại rằng pháp sĩ Mạc Lan đã đột phá cực hạn thi triển pháp thuật, nghiên cứu ra cách trong nháy mắt thi triển đại uy lực, khiến các thế lực lớn Thiên Nam liên thủ cũng chỉ tự bảo vệ.","anchor":"Nghiên cứu ra không ít thứ có thể trong nháy mắt thi triển ra đại uy lực"}]},"nguon":["@c0679"]},{"id":"tho-don-phap","name":"Thổ Độn pháp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông độn thuật hệ thổ, cho phép hai người biến mất trên mặt đất với tốc độ cực nhanh khiến tu sĩ xung quanh kinh hãi.","detail":"Hàn Lập thi triển thổ độn thuật đưa Tôn Hỏa biến mất tại chỗ, hoàng quang chớp động rồi cả hai biến mất trên mặt đất. Tu sĩ xung quanh chưa từng thấy thổ độn thần diệu đến vậy.","congNang":["Cho phép di chuyển dưới lòng đất, hai người biến mất trên mặt đất với tốc độ cực nhanh"],"tabs":{"tienTrinh":[{"chuong":"@c0680","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng tại Điền Thiên Thành","text":"Hàn Lập dùng thổ độn thuật đưa Tôn Hỏa biến mất tại chỗ, tu sĩ xung quanh kinh hãi vì chưa từng thấy thổ độn thần diệu đến vậy.","anchor":"hoàng quang chớp động, thân hình hai người trên mặt đất bỗng biến mất không thấy"}]},"nguon":["@c0680"]},{"id":"thuong-co-khoi-loi-thuat","name":"Thượng cổ khôi lỗi thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật luyện chế","phamCap":"Thượng cổ","hePhai":"","soHuu":["Thiên Tinh Chân Nhân"],"blurb":"Thuật luyện chế khôi lỗi thú có từ thời thượng cổ, được Thiên Tinh Chân Nhân cùng bằng hữu phát hiện từ di vật cổ tu sĩ. Khôi lỗi thú tạo ra có uy lực vô cùng lợi hại, cần hồn thạch và tài liệu trân quý.","detail":"Thuật luyện chế khôi lỗi thú thời thượng cổ. Thiên Tinh Chân Nhân cùng vài bằng hữu phát hiện từ di vật thượng cổ tu sĩ. Khôi lỗi thú được tạo ra có uy lực vô cùng lợi hại nhưng tài liệu luyện chế vô cùng trân quý, nguyên liệu cốt lõi là hồn thạch — thứ rất khó kiếm. Hàn Lập đàm phán bằng hồn thạch để được xem thuật này.","thuocTinh":"Luyện chế khôi lỗi","nguonGoc":"Di vật thượng cổ tu sĩ, Thiên Tinh Chân Nhân cùng bằng hữu phát hiện","yeuCau":"Hồn thạch + tài liệu trân quý","uyLuc":"Khôi lỗi thú tạo ra uy lực vô cùng lợi hại","dacDiem":"Thuật thượng cổ, tài liệu trân quý, hồn thạch khó kiếm","congNang":["Luyện chế khôi lỗi thú uy lực mạnh mẽ"],"nguoiTu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0681","tangDatToi":"","trangThai":"dang-nghien-cuu"}],"tabs":{"tienTrinh":[{"chuong":"@c0681","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện qua đàm phán Hàn Lập – Thiên Tinh Chân Nhân","text":"Thiên Tinh Chân Nhân xác nhận cùng bằng hữu phát hiện thuật luyện chế khôi lỗi thượng cổ từ di vật cổ tu sĩ. Hàn Lập hé lộ từng tìm hài cốt khôi lỗi thú trong động phủ, đàm phán bằng hồn thạch để xem thuật.","anchor":"phát hiện ra một ít thuật luyện chế khôi lỗi thời thượng cổ"}]},"dinhDanh":"goc","nguon":["@c0681"]},{"id":"bi-thuat-lien-thu-hop-nhat-than-thuc","name":"Bí thuật liên thủ hợp nhất thần thức","loai":"bi-thuat","loaiLabel":"Bí thuật","soHuu":["Vương Thiền","Yến Như Yên"],"blurb":"Bí thuật cho phép hai người liên thủ hợp nhất thần thức, trong khoảng thời gian ngắn đạt sức mạnh thần thức ngang Nguyên Anh Kỳ dù bản thân chỉ ở Kết Đan Hậu Kỳ.","detail":"Vương Thiền và Yến Như Yên tinh thông bí thuật này. Khi liên thủ, hai thần thức Kết Đan Hậu Kỳ được hợp nhất, sức mạnh thần thức trong khoảng thời gian ngắn không kém Nguyên Anh Kỳ. Đây là lý do Nam Lũng Hầu mời hai vãn bối này tham gia mật hội dù chỉ ở Kết Đan.","congNang":["Hợp nhất thần thức hai người, đạt sức mạnh thần thức ngang Nguyên Anh Kỳ trong thời gian ngắn"],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0683","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Yến Như Yên","tuChuong":"@c0683","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0683","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến tại mật hội","text":"Nam Lũng Hầu giải thích hai vãn bối Quỷ Linh Môn (Vương Thiền và Yến Như Yên) tinh thông bí thuật liên thủ hợp nhất thần thức, khi liên thủ sức mạnh thần thức không kém Nguyên Anh Kỳ.","anchor":"một khi liên thủ thì có thể hợp nhất hai thần thức lại với nhau trong khoảng thời gian cũng không kém gì với ta đâu"}]},"nguon":["@c0683"]},{"id":"thai-dieu-than-cam","name":"Thái Diệu Thần Cấm","cn":"","loai":"bi-thuat","loaiLabel":"Thượng cổ cấm chế / Pháp trận","phamCap":"Thượng cổ thất truyền (thập đại thượng cổ cấm chế)","hePhai":"","soHuu":["Thương Khôn Thượng Nhân"],"blurb":"Một trong thập đại thượng cổ cấm chế đã thất truyền, bảo vệ bên ngoài động phủ Thương Khôn Thượng Nhân ở vòng ngoài Mộ Lan thảo nguyên.","detail":"Pháp trận thượng cổ tạo ra cấm chế phòng hộ cực kỳ kiên cố. Nam Lũng Hầu và Bạch sam lão giả công kích mấy tháng liền không phá nổi. Sau nghiên cứu phát hiện cần tám vị tu sĩ thần thức cường đại dùng thần thức biến hoá thần thông để giải cấm chế, ước tính một ngày có thể phá.","congNang":["Cấm chế phòng hộ động phủ, miễn nhiễm công kích thần thông thông thường, chỉ có thể phá bằng tám thần thức cường đại đồng thời biến hoá thần thông"],"tabs":{"tienTrinh":[{"chuong":"@c0684","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và nghiên cứu","text":"Nam Lũng Hầu và Bạch sam lão giả tìm được động phủ Thương Khôn Thượng Nhân ở vòng ngoài Mộ Lan thảo nguyên nhưng bên ngoài có Thái Diệu Thần Cấm — thượng cổ pháp trận thất truyền. Hai người công kích mấy tháng không phá nổi. Sau nghiên cứu xác định cần tám tu sĩ thần thức cường đại phá giải. Vương Thiên Cổ nhận ra đây thuộc thập đại thượng cổ cấm chế.","anchor":"phát hiện ra pháp trận này tạo ra cấm chế đúng là một loại thượng cổ pháp trận đã bị thất truyền"}]},"capNhatToi":"@c0684","nguon":["@c0684"]},{"id":"huyet-linh","name":"Huyết Linh","cn":"血灵","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Vương Thiền","Yến Như Yên"],"blurb":"Công pháp tà thuật do vợ chồng Vương Thiền tu luyện, uy lực cao thâm. Khi đột phá tầng thứ bảy, người tu sẽ tương đương kết thành Nguyên Anh.","detail":"Vương Thiên Cổ đánh giá uy lực Huyết Linh cao thâm, tiết lộ khi đột phá tới tầng thứ bảy thì vợ chồng Vương Thiền tương đương như người kết thành Nguyên Anh. Vợ chồng Vương Thiền hiện chưa đạt tầng 7.","congNang":["Khi đột phá tầng 7, người tu tương đương kết thành Nguyên Anh"],"cacTang":[{"ten":"Tầng 7","moTa":"Tương đương Nguyên Anh, vợ chồng Vương Thiền sắp đột phá","chuong":"@c0685"}],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0685","tangDatToi":"Dưới tầng 7","trangThai":"dang-tu"},{"ten":"Yến Như Yên","tuChuong":"@c0685","tangDatToi":"Dưới tầng 7","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0685","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ tầng 7 tương đương Nguyên Anh","text":"Vương Thiên Cổ tiết lộ Huyết Linh khi đột phá tầng thứ bảy sẽ khiến người tu tương đương kết thành Nguyên Anh, vợ chồng Vương Thiền sắp đạt mốc này.","anchor":"Huyết Linh sau khi đột phá tới tầng thứ bảy thì hai người các ngươi cũng tương đương như người kết thành nguyên anh"}]},"dinhDanh":"goc","nguon":["@c0685"]},{"id":"phong-linh-thuat-hong-tran-van-truong","name":"Phong Linh Thuật — Hồng Trần Vạn Trượng","cn":"風靈術 — 紅塵萬丈","loai":"linh-thuat","loaiLabel":"Linh thuật","phamCap":"Không rõ","hePhai":"Người Mộ Lan","soHuu":["Người Mộ Lan"],"blurb":"Linh thuật đặc trưng của pháp sĩ Người Mộ Lan, tạo bão cát khổng lồ ngăn cản thần thức tu sĩ dò xét, đồng thời dùng cuồng phong cát vàng hộ thân vây địch.","detail":"Phong Linh Thuật tạo ra hoàng phong (bão cát vàng) bao phủ diện tích cực lớn. Khi thần thức xâm nhập vào bão cát, chỉ cảm ứng được hơn mười trượng trước khi bị sương mù che phủ. Cuồng phong cát vàng vừa có tác dụng hộ thân vừa vây khốn địch nhân. Lần này quy mô mở rộng gấp trăm ngàn lần bình thường, bao hàm nhiều phong trụ bên trong ẩn tàng pháp sĩ di chuyển. Nam Lũng Hầu nhận ra đây là linh thuật “Hồng Trần Vạn Trượng” mà Người Mộ Lan từng dùng khi đấu pháp với hắn trước đây.","thuocTinh":"Phong","nguonGoc":"Linh thuật bản địa của Người Mộ Lan","congNang":["Tạo bão cát khổng lồ ngăn cản thần thức tu sĩ dò xét","Cuồng phong cát vàng hộ thân vây địch"],"tabs":{"tienTrinh":[{"chuong":"@c0686","loai":"thi triển","importance":"major","giaiDoan":"Đội tiên phong Mộ Lan thi triển quy mô cực lớn","text":"Đội tiên phong Người Mộ Lan thi triển Phong Linh Thuật Hồng Trần Vạn Trượng với quy mô gấp trăm ngàn lần bình thường, tạo bão cát cao hơn trăm trượng bao phủ diện tích cực lớn, bên trong ẩn tàng nhiều pháp sĩ.","anchor":"Phong Linh Thuật của người Mộ Lan! Trước kia khi cùng ta đấu pháp đã thi triển loại linh thuật “Hồng Trần Vạn Trượng” này"}]},"nguon":["@c0686"]},{"id":"ao-tran-cat-vang","name":"Ảo trận cát vàng","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Mộ Lan — Hoàng Sa Bộ","soHuu":["Hoàng Sa Bộ"],"blurb":"Cấm chế ảo trận do pháp sĩ Mộ Lan Hoàng Sa Bộ bố trí vội vã để vây khốn nhóm tu sĩ. Uy lực yếu, bị nhóm Nguyên Anh xé rách dễ dàng như bạc chỉ bàn.","detail":"Trận pháp vây khốn, cấm chế khu vực bão cát. Do bố trí vội nên uy lực cực yếu so với nhóm tu sĩ Nguyên Anh, bị phá hủy dễ dàng.","congNang":["Vây khốn, cấm chế khu vực bão cát"],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá hủy","text":"Hoàng Sa Bộ bố trí vội vã vây nhóm tu sĩ Hàn Lập. Nhóm Nguyên Anh hợp lực tấn công, cấm chế bị xé rách dễ dàng như bạc chỉ bàn.","anchor":"cấm chế này giống như bạc chỉ bàn bị mọi người công kích dễ dàng bị xé rách nát bấy"}]},"nguon":["@c0687"]},{"id":"minh-thanh-linh-muc","name":"Minh Thanh Linh Mục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông mắt nhờ rửa bằng Minh Thanh Linh Thủy nhiều lần, truyền linh lực vào mắt để nhìn xuyên bão cát, kết giới che mắt, phát hiện kẻ ẩn thân.","detail":"Hàn Lập truyền linh lực vào mắt thi triển thần thông, nhìn xuyên bão cát trong Hoàng Sa Phong Trận, phát hiện vòng tròn bóng đen đường kính hơn mười trượng chứa mấy người ẩn thân giám sát. Rót thêm linh lực thì bóng đen chia rõ ra nhưng đó là cực hạn, không thấy hoàn toàn rõ chi tiết bên trong. Mắt thường không thấy gì.","congNang":["Nhìn xuyên bão cát, kết giới che mắt, phát hiện kẻ ẩn thân"],"dacDiem":"Có cực hạn — rót thêm linh lực vẫn không thấy hoàn toàn rõ chi tiết bên trong","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0688","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0688","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển thực chiến","text":"Hàn Lập truyền linh lực vào mắt thi triển Minh Thanh Linh Mục trong Hoàng Sa Phong Trận, nhìn xuyên bão cát phát hiện vòng tròn bóng đen chứa mấy người ẩn thân giám sát có pháp lực vượt Nguyên Anh.","anchor":"Minh Thanh Linh Mục kia thần thông ra sao"}]},"nguon":["@c0688"]},{"id":"don-tho-thuat","name":"Độn thổ thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hán tử da ngăm đen"],"blurb":"Bí thuật trốn chạy bằng cách chui vào lòng đất biến mất.","detail":"Hán tử da ngăm đen toàn thân toát hoàng linh hỏa, thi triển độn thổ thuật chui vào lòng đất không còn bóng dáng để chạy trốn khi bị Ngự Phong Xa truy đuổi.","nguon":["@c0688"]},{"id":"trung-giap-phe-kim-trung","name":"Trùng giáp Phệ Kim Trùng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Cách thức sử dụng Tam Sắc Phệ Kim Trùng kết thành giáp trùng bọc toàn thân phòng hộ, trong suốt phát thanh quang.","detail":"Hàn Lập thả Tam Sắc Phệ Kim Trùng từ túi linh thú, dùng pháp quyết khiến trùng vân hạ xuống bọc lấy thân mình, kết thành giáp trùng trong suốt phát thanh quang nhàn nhạt. Đây là phương thức phòng hộ hoàn toàn mới, lần đầu được sử dụng.","congNang":["Kết giáp trùng bọc toàn thân phòng hộ, trong suốt phát thanh quang"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0689","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0689","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập lần đầu dùng Tam Sắc Phệ Kim Trùng kết thành giáp trùng bọc toàn thân phòng hộ khi nghênh chiến Mục lão giả trên Mộ Lan thảo nguyên.","anchor":"tam sắc trùng hiện thành giáp trùng trên người Hàn Lập, trong suốt cổ phát, thanh quang lóe lên nhàn nhạt"}]},"nguon":["@c0689"]},{"id":"bang-tinh-thuat","name":"Băng Tinh Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Pháp sĩ","soHuu":["Mục lão giả"],"blurb":"Linh thuật của pháp sĩ, kết thủ ấn phóng pháp quyết biến linh quang thành vô số băng tinh huyền tinh hàn khí cỡ nắm tay bao phủ hơn mười trượng, bắn tới đối thủ.","detail":"Giống Băng Vũ Thuật của tu sĩ ngũ hành nhưng thực chất dùng huyền tinh hàn khí tự thân tu luyện, sắc bén và kỳ hàn hơn nhiều, có thể đóng băng và nghiền nát cả hộ thân pháp bảo. Bị hoa lam cổ bảo và trùng tráo Phệ Kim Trùng của Hàn Lập hóa giải hoàn toàn.","thuocTinh":"Băng","nguonGoc":"Linh thuật riêng của hệ thống pháp sĩ, khác thuật pháp tu sĩ thông thường","uyLuc":"Sắc bén và kỳ hàn hơn Băng Vũ Thuật, có thể đóng băng và nghiền nát hộ thân pháp bảo","dacDiem":"Dùng huyền tinh hàn khí tự thân tu luyện thay vì linh lực ngũ hành thông thường","congNang":["Phóng vô số băng tinh huyền tinh hàn khí sắc bén, đóng băng + nghiền nát mục tiêu"],"nguoiTu":[{"ten":"Mục lão giả","tuChuong":"@c0690","tangDatToi":"Thuần thục","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển trong trận đấu với Hàn Lập","text":"Mạc lão giả kết thủ ấn phóng pháp quyết, linh quang lam sắc co rút rồi bạo liệt vỡ ra thành vô số băng tinh cỡ nắm tay trải rộng hơn mười trượng, bắn tới Hàn Lập. Bị hoa lam cổ bảo hút thu và trùng tráo Phệ Kim Trùng cản lại hoàn toàn.","anchor":"chính là bị đạo hữu dùng vật ấy phá vỡ"}]},"nguon":["@c0690"]},{"id":"loi-don-chi-thuat","name":"Lôi Độn Chi Thuật","cn":"雷遁之术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi thuộc tính","soHuu":["Mục lão giả"],"blurb":"Thuật lôi độn thuần túy, tốc độ truy đuổi tầm xa vượt trội hơn Phong Lôi Sí.","detail":"Mục lão giả dùng Lôi Độn Chi Thuật (hóa lam mang) để Nguyên Anh thoát thân sau khi thân xác bị hủy. Hàn Lập thừa nhận Phong Lôi Sí không bằng Lôi Độn Chi Thuật thuần túy trong việc truy đuổi tầm xa.","congNang":["Lôi độn di chuyển tốc độ cực cao, ưu thế truy đuổi tầm xa"],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"thi triển","importance":"normal","giaiDoan":"Nguyên Anh Mục lão giả thoát thân","text":"Nguyên Anh Mục lão giả hóa lam mang dùng Lôi Độn Chi Thuật chạy trốn cực nhanh sau khi thân xác bị đóng băng hủy diệt. Hàn Lập thừa nhận Phong Lôi Sí không bằng thuật này về truy đuổi.","anchor":"Dù hắn có thần thông của Phong Lôi Sí, cũng không thể bằng Lôi Độn Chi Thuật"}]}},{"id":"tinh-bang-thuan","name":"Tinh Băng Thuẫn","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Mục lão giả"],"blurb":"Băng thuẫn hộ thể thông linh tự động, có thể đóng băng vật thể tiếp xúc.","detail":"Linh quang lam ly thể hóa thành băng thuẫn bay khắp tứ phía bao bọc, thông linh tự động hộ chủ. Đóng băng được Thanh Minh Châm khi tiếp xúc biến thành băng châm rơi xuống, nhưng không chống nổi Kiền Lam Băng Diễm.","congNang":["Tự động hộ thể","Đóng băng vật thể tiếp xúc"],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"thi triển","importance":"normal","giaiDoan":"Mục lão giả hộ thể chống Hàn Lập","text":"Băng thuẫn lơ lửng quanh thân Mục lão giả, thông linh tự động hộ chủ, đóng băng được Thanh Minh Châm nhưng không chống nổi Kiền Lam Băng Diễm.","anchor":"băng thuẫn lơ lửng quang thân, thông linh tự động hộ chủ, bạch quang tự động che trước mặt lão già"}]}},{"id":"bi-phap-don-thuat-quy-linh-mon","name":"Bí pháp độn thuật Quỷ Linh Môn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiên Cổ","Vương Thiền"],"blurb":"Bí pháp độn thuật của Quỷ Linh Môn, cần liên thủ nhiều người thi triển để tăng tốc độ thoát thân vượt trội.","detail":"Vương Thiên Cổ cùng hai vãn bối liên thủ thi triển bí pháp này để bỏ xa pháp sĩ Mộ Lan truy đuổi. Yêu cầu ba người phối hợp, tốc độ độn thuật vượt xa bình thường.","nguoiTu":[{"ten":"Vương Thiên Cổ","tuChuong":"@c0692","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0692","loai":"thi triển","importance":"normal","giaiDoan":"Liên thủ ba người thoát truy đuổi","text":"Vương Thiên Cổ cùng hai vãn bối liên thủ thi triển bí pháp độn thuật môn phái để bỏ xa pháp sĩ Mộ Lan đuổi theo.","anchor":"Ta cùng hai vị vãn bối liên thủ thi triển bí pháp độn thuật của môn phái"}]},"nguon":["@c0692"]},{"id":"thanh-truc-bach-luyen-hoa","name":"Thanh Trúc Bách Luyện Hỏa","cn":"青竹百炼火","aliases":["Sợi tơ lửa xanh"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa","soHuu":["Hàn Lập"],"blurb":"Ngọn lửa xanh nhỏ như tơ được phun từ miệng, có khả năng xuyên thủng hộ thể quang tráo của đối phương, uy lực cực mạnh.","detail":"Hàn Lập há miệng phun ra ngọn lửa màu xanh nhỏ như sợi tơ, sợi tơ lửa xuyên thủng bạch quang tráo hộ thân của tu sĩ họ Vưu mà không hề trở ngại, bắn thẳng vào người đối phương. Thuộc loại hỏa hệ thần thông, dạng tơ lửa cực nhỏ nhưng xuyên phá lực cực mạnh.","congNang":["Phun từ miệng dạng sợi tơ lửa xanh, xuyên thủng hộ thể quang tráo đối phương @c0699"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0699","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0699","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập há miệng phun sợi tơ lửa xanh xuyên thủng bạch quang tráo hộ thân tu sĩ họ Vưu, bắn trúng người đối phương.","anchor":"sợi tơ không hề trở ngại xuyên thùng bạch quang tráo bắn thẳng đến trên người tên tu sĩ họ Vưu"}]},"nguon":["@c0699"]},{"id":"huyet-linh-dai-phap","name":"Huyết Linh Đại Pháp","cn":"血灵大法","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiền","Yến Như Yên"],"blurb":"Bí pháp hợp lực của Quỷ Linh Môn, hai người dung hòa huyết vụ thành huyết quang tím che thân, phát ra tiếng quỷ khóc thê lương.","detail":"Vương Thiền và Yến Như Yên hợp lực thi triển, huyết vụ hai người dung hòa thành huyết quang màu tím, cả hai biến mất trong sương mù tím, phát ra tiếng quỷ khóc thê lương.","congNang":["Hợp lực tạo huyết vụ tím che thân, phát ra quỷ khóc thê lương","Tạo huyết vụ hộ thể khi liên thủ thi triển"],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0700","tangDatToi":"","trangThai":"dang-co"},{"ten":"Yến Như Yên","tuChuong":"@c0700","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0700","loai":"thi triển","importance":"normal","giaiDoan":"Hợp lực lần đầu lộ diện","text":"Vương Thiền ép Yến Như Yên hợp lực thi triển, huyết vụ hai người dung hòa thành huyết quang tím, biến mất trong sương mù, phát ra quỷ khóc thê lương.","anchor":"huyết vụ trên người cùng huyết vụ của Vương Thiền, không hề khúc mắc mà dung hòa với nhau, hình thành một cổ huyết quang màu tím"},{"chuong":"@c0702","loai":"thi triển","importance":"normal","giaiDoan":"Liên thủ thi triển lần đầu được nhắc","text":"Yến Như Yên kể lại hai người đã liên thủ thi triển Huyết Linh Đại pháp hộ thể huyết vụ nhưng bí thuật đối phương xuyên thủng hoàn toàn.","anchor":"Ta cùng phu quân liên thủ thi triển ra Huyết Linh Đại pháp hộ thể huyết vụ"}]},"nguon":["@c0700","@c0702"]},{"id":"van-xich-nhat-tuyen","name":"Vạn Xích Nhất Tuyến","cn":"万尺一线","loai":"bi-thuat","loaiLabel":"Bí thuật / Độn thuật","phamCap":"","hePhai":"","soHuu":["Thương Khôn Thượng Nhân","Nam Lũng Hầu"],"blurb":"Bí thuật tự tạo của Thương Khôn Thượng Nhân, biến độn quang thành tuyến tơ tằm cực nhỏ thu liễm hoàn toàn khí tức khiến thần thức không thể truy tung, nhưng đại giá cực lớn.","detail":"Trong nháy mắt biến độn quang thành tuyến tơ tằm cực nhỏ, thu liễm hoàn toàn khí tức khiến người ta không thể nào truy tung bằng thần thức. Đại giá: tốn phần lớn nguyên khí và lượng lớn tinh huyết, không duy trì được lâu. Nam Lũng Hầu thi triển khi đào thoát khỏi Hư Thiên điện, sau đó bị đánh giá dù trăm năm cũng không giữ nổi cảnh giới Nguyên Anh Trung Kỳ.","nguon":["@c0701"],"nguonGoc":"Bí thuật tự tạo của Thương Khôn Thượng Nhân","thuocTinh":"","uyLuc":"Thu liễm hoàn toàn khí tức, vô pháp truy tung bằng thần thức","dacDiem":"Đại giá cực lớn: tốn phần lớn nguyên khí + lượng lớn tinh huyết","congNang":["Biến độn quang thành tuyến tơ tằm cực nhỏ, thu liễm hoàn toàn khí tức, khiến thần thức không cảm ứng được"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"thi triển","importance":"major","giaiDoan":"Nam Lũng Hầu thi triển đào thoát","text":"Nam Lũng Hầu thi triển Vạn Xích Nhất Tuyến khi đào thoát khỏi Hư Thiên điện, biến kim hồng thành tơ tằm cực nhỏ thu liễm khí tức biến mất, trả giá bằng phần lớn nguyên khí và tinh huyết.","anchor":"Đem độn quang hóa thành tuyến tơ tằm cực nhỏ khí tức thu liễm hoàn toàn, làm cho người ta không thể nào truy tung"}]}},{"id":"don-thuat-ngan-nguyet-lang-toc","name":"Độn thuật Ngân Nguyệt Lang Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt Lang Tộc","soHuu":["Ngân Nguyệt"],"blurb":"Độn thuật ẩn thân đặc hữu của Ngân Nguyệt Lang Tộc, thần diệu nhưng cần vật che dấu linh khí hỗ trợ mới qua mắt được thần thức tu sĩ Nguyên Anh.","detail":"Ngân Nguyệt sử dụng độn thuật này để ẩn thân lấy hộp ngọc ở Cổ Bảo tầng hai. Bản thân độn thuật rất thần diệu trong việc che dấu hình thể, nhưng không che dấu được linh khí — cần kết hợp với hộp ngọc có tính năng che dấu linh khí mới có thể qua mắt thần thức các tu sĩ Nguyên Anh cấp.","congNang":["Ẩn thân che dấu hình thể, cần vật hỗ trợ che linh khí để qua mắt Nguyên Anh @c0703"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0703","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng lấy hộp ngọc Cổ Bảo","text":"Ngân Nguyệt dùng độn thuật Lang Tộc ẩn thân lấy ba hộp ngọc ở Cổ Bảo tầng hai, kết hợp tính năng che linh khí của hộp ngọc để qua mắt thần thức tu sĩ Nguyên Anh.","anchor":"Ngân Nguyệt Lang Tộc độn thuật mặc dù thần diệu, nhưng chính yếu là do hộp ngọc này có thể che dấu linh khí"}]},"nguon":["@c0703"]},{"id":"vong-nguyet-quyet","name":"Vọng Nguyệt quyết","cn":"望月诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Thương Khôn Thượng Nhân"],"blurb":"Công pháp thần thông của Thương Khôn Thượng Nhân ghi trong ngọc giản. Hàn Lập không thể tu luyện nhưng có vài bí thuật và kinh nghiệm tu luyện đáng tham khảo.","detail":"Ghi chép trong ngọc giản của Thương Khôn Thượng Nhân, bao gồm công pháp chính cùng một số bí thuật và kinh nghiệm tu luyện phụ trợ. Hàn Lập không phù hợp tu luyện công pháp chính nhưng đánh giá bí thuật kèm theo có giá trị tham khảo.","nguonGoc":"Thương Khôn Thượng Nhân sáng tạo hoặc truyền thừa","trangThai":"ton-tai","nguoiTu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0704","tangDatToi":"","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong ngọc giản","text":"Hàn Lập xem ngọc giản chiến lợi phẩm, phát hiện chứa công pháp Vọng Nguyệt quyết của Thương Khôn Thượng Nhân. Không tu luyện được nhưng tham khảo bí thuật và kinh nghiệm.","anchor":"công pháp Vọng Nguyệt quyết trong đó ta không có cách nào tu luyện được"}]},"nguon":["@c0704"]},{"id":"cau-linh-thuat","name":"Câu Linh thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Pháp sĩ","soHuu":["Pháp sĩ họ Đàm"],"blurb":"Linh thuật pháp sĩ, dùng đạn hoàn bắn xuống đất triệu hoán Câu Linh Thổ Long bằng thổ thạch, linh khí đến từ đạn hoàn trên trán thổ long.","detail":"Pháp sĩ bắn đạn hoàn vàng xuống mặt đất, hô khẩu quyết, triệu hoán hai con cầu long màu vàng dài vài chục trượng từ dưới đất bay ra. Thổ long hoàn toàn do thổ thạch hình thành nhưng sống động như vật sống, linh khí đến từ đạn hoàn nằm trên trán. Bị Hàn Lập dùng Kiềm Lam Băng Diễm đông cứng rồi kiếm khí kích nát dễ dàng.","congNang":["Triệu hoán thổ long từ đất đá, cần đạn hoàn làm linh hạch"],"nguoiTu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Pháp sĩ họ Đàm triệu hoán hai con Câu Linh Thổ Long bằng đạn hoàn vàng, bị Hàn Lập phá hủy dễ dàng bằng Kiềm Lam Băng Diễm và kiếm khí.","anchor":"hai con cầu long màu vàng dài vài chục trượng chui từ dưới mặt đất bay ra"}]},"nguon":["@c0705"]},{"id":"mong-dan-thuat","name":"Mộng Dẫn thuật","cn":"梦引术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kỹ thuật moi ký ức/thông tin từ người bị khống chế, phối hợp cùng huyễn thuật để tăng hiệu quả.","detail":"Hàn Lập dùng Mộng Dẫn thuật phối hợp cùng huyễn thuật của Ngân Nguyệt để moi hết thông tin ký ức từ ba đệ tử Yểm Nguyệt Tông đã bị đánh ngất. Có thể khai thác được ký ức chi tiết về nội bộ tông môn.","congNang":["Moi ký ức/thông tin từ người bị khống chế, phối hợp huyễn thuật tăng hiệu quả"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0709","tangDatToi":"","trangThai":"thành thục"}],"tabs":{"tienTrinh":[{"chuong":"@c0709","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập phối hợp Mộng Dẫn thuật cùng huyễn thuật của Ngân Nguyệt moi hết thông tin ký ức ba đệ tử Yểm Nguyệt Tông.","anchor":"phối hợp cùng với Mộng Dẫn thuật của ta để moi hết ra những thông tin đi"}]},"nguon":["@c0709"]},{"id":"khon-tam-thuat","name":"Khốn Tâm Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Yểm Nguyệt Tông","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"blurb":"Pháp thuật cấm chế do đại trưởng lão Yểm Nguyệt Tông dùng máu huyết bản thân hạ chú, mấu chốt ở một khối lệnh bài. Trong vòng trăm dặm có thể khống chế đối tượng, mức độ tùy chênh lệch tu vi.","detail":"Khốn Tâm Thuật sử dụng máu huyết của chính người hạ chú, mấu chốt nằm ở một khối lệnh bài. Nếu không phá hủy lệnh bài, trong phạm vi trăm dặm nạn nhân bị khống chế. Khi chênh lệch tu vi giữa người hạ và người chịu không lớn, chỉ khống chế được động tác đơn giản, không thể sử dụng pháp lực của nạn nhân. Dự kiến dùng trong đại điển ép buộc.","congNang":["Khống chế đối tượng bị hạ chú trong phạm vi trăm dặm, mức độ tùy chênh lệch tu vi @c0712"],"nguoiTu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0712","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0712","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Nam Cung Uyển tiết lộ bị đại trưởng lão sư tỷ hạ Khốn Tâm Thuật bằng máu huyết, mấu chốt ở lệnh bài, khống chế trong trăm dặm. Hàn Lập nhận lời đi lấy lệnh bài.","anchor":"Khốn Tâm Thuật mà vị sư tỷ kia hạ là thật sự khó phá giải"}]},"nguon":["@c0712"]},{"id":"thai-am-bo-duong-thuat","name":"Thuật Thái Âm Bổ Dương","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Tà thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Ngụy Ly Thần"],"blurb":"Tà thuật mà Ngụy Ly Thần lén tu luyện, ám chỉ ý đồ xấu khi cầu hôn Nam Cung Uyển.","detail":"Ngụy Ly Thần lén lút tu luyện thuật Thái Âm Bổ Dương, thể hiện bản chất ngụy quân tử và ý đồ không trong sáng khi theo đuổi Nam Cung Uyển.","nguon":["@c0712"]},{"id":"tran-ky-tran-ban","name":"Trận kỳ trận bàn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Kết Đan cấp","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ trận kỳ trận bàn Hàn Lập luyện từ thời Kết Đan Kỳ, có thể tập trung uy lực trong phạm vi hẹp và ngụy trang bí mật, nhưng uy lực không đủ đối phó tu sĩ Nguyên Anh Kỳ, chỉ có tác dụng phụ trợ.","detail":"Hàn Lập lấy trận kỳ trận bàn bố trí khắp đại sảnh động phủ Nam Cung Uyển, khống chế uy lực trong phạm vi hẹp và ngụy trang phi thường bí mật, khó phát hiện nếu không dùng thần thức tìm kỹ. Tự nhận thức đây là trận pháp luyện từ thời Kết Đan, uy lực chỉ đủ phụ trợ chứ không đủ đối phó Nguyên Anh Kỳ.","congNang":["Tập trung uy lực trận pháp trong phạm vi hẹp","Ngụy trang bí mật, khó phát hiện"],"tabs":{"tienTrinh":[{"chuong":"@c0713","loai":"dùng","importance":"normal","giaiDoan":"Bố trí phục kích sư tỷ Yểm Nguyệt Tông","text":"Hàn Lập bố trí trận kỳ trận bàn khắp đại sảnh để phục kích sư tỷ Nguyên Anh trung kỳ, tập trung uy lực trong phạm vi hẹp và ngụy trang bí mật.","anchor":"Trận kỳ trận bàn này đều là khi Hàn Lập đang có tu vi Kết Đan Kỳ luyện thành"}]},"nguon":["@c0713"]},{"id":"phap-tran-cam-che-dai-sanh","name":"Pháp trận cấm chế đại sảnh","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp cấm chế do Hàn Lập bố trí sẵn trong đại sảnh thính đường động phủ Nam Cung Uyển, kích hoạt bằng hai đạo pháp quyết xanh đỏ đánh vào hai cột trụ để khốn đại trưởng lão.","detail":"Hàn Lập đã chuẩn bị trước pháp trận cấm chế trong đại sảnh. Khi đại trưởng lão niệm chú cố phát động cấm chế lệnh bài, Hàn Lập bắn hai đạo pháp quyết một xanh một đỏ vào hai cột trụ gần đó, kích hoạt trận pháp phối hợp với Kinh Long chung tạo thế bao vây.","congNang":["Khốn/cấm chế đối phương trong phạm vi đại sảnh"],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu kích hoạt","text":"Hàn Lập bắn hai đạo pháp quyết xanh đỏ vào hai cột trụ, kích hoạt pháp trận cấm chế đã bố trí sẵn trong đại sảnh để khốn đại trưởng lão Yểm Nguyệt Tông.","anchor":"Hai đạo pháp quyết một xanh một đỏ phân biệt đánh vào hai cột trụ ở gần đó"}]},"nguon":["@c0714"]},{"id":"luan-hoi-than-quang","name":"Luân Hồi Thần Quang","cn":"轮回神光","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp cao","hePhai":"","soHuu":["Nam Cung Uyển"],"blurb":"Thần thông cấp cao của Nam Cung Uyển, hiện vầng sáng đỏ đậm lớn trên đỉnh đầu như phật quang lưu chuyển, uy lực khiến Nguyên Anh kỳ tu sĩ kiêng dè nhưng có đại giá cho người dùng.","detail":"Nam Cung Uyển niệm chú thi triển, trên đỉnh đầu hiện vầng sáng đỏ đậm lớn lưu chuyển. Sư tỷ (Đại trưởng lão Yểm Nguyệt Tông) kinh hãi gọi đây là hành động liều mạng, cho thấy thần thông này có đại giá hoặc nguy hiểm cho chính người thi triển.","nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0715","tangDatToi":"","trangThai":"thi triển"}],"congNang":["Hiện vầng sáng đỏ đậm phật quang trên đỉnh đầu, uy lực cấp cao khiến Nguyên Anh kỳ tu sĩ kiêng dè"],"dacDiem":"Có đại giá cho người dùng, bị coi là liều mạng khi vận dụng","tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Nam Cung Uyển niệm chú thi triển Luân Hồi Thần Quang, hiện vầng sáng đỏ đậm trên đỉnh đầu khiến sư tỷ biến sắc kinh hãi.","anchor":"Luân Hồi Thần Quang! Nam Cung sư muội, ngươi thật muốn liều mạng sao? Dám vận dụng thần thông này?"}]},"nguon":["@c0715"]},{"id":"hoa-kiem-vi-ti","name":"Hóa kiếm vi ti","cn":"化劍為絲","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Kiếm tu","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"blurb":"Kiếm thuật biến phi kiếm thành hàng ngàn sợi tơ bạc bén nhọn tấn công diện rộng, đủ sức chém rơi Phệ Kim Trùng nhiều lần.","detail":"Băng lãnh nữ tử phun ra tiểu kiếm bạc rồi bắt quyết, kiếm hóa thành ngàn đạo hào quang nhỏ như tơ bén nhọn liên tục chém đối thủ. Hàn Lập nhận ra đây là kỹ thuật đặc trưng của kiếm tu.","congNang":["Biến phi kiếm thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng"],"nguoiTu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0716","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0716","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Băng lãnh nữ tử phun ra tiểu kiếm bạc, thi triển Hóa kiếm vi ti hóa thành ngàn sợi tơ bạc bén nhọn chém rơi Phệ Kim Trùng nhiều lần. Hàn Lập nhận ra đây là kỹ thuật kiếm tu.","anchor":"Hóa kiếm vi ti! Hàn Lập nhướng mày lẩm bẩm"}]},"nguon":["@c0716"]},{"id":"an-bi-cam-che-trong-phu","name":"Ẩn bí cấm chế trong phủ","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế / Trận pháp","phamCap":"Không rõ","hePhai":"Yểm Nguyệt Tông","soHuu":["Nam Cung Uyển"],"blurb":"Cấm chế ẩn bí được bố trí sẵn trong đại sảnh động phủ Nam Cung Uyển, kích hoạt bằng chú ngữ, tạo hồng quang mạc phong tỏa toàn sảnh.","detail":"Nam Cung Uyển dùng chú ngữ kích hoạt, hồng quang mạc xuất hiện trên tường, đỉnh và nền đại sảnh. Quang mạc có tính khắc chế hoàng quang, hút và bao vây đối phương. Bị hắc bạch kiếm khí phá vỡ nhưng đã tạm chặn được tu sĩ Nguyên Anh trung kỳ.","congNang":["Hồng quang mạc phong tỏa toàn sảnh, khắc chế hoàng quang, bao vây đối phương"],"nguon":["@c0717"]},{"id":"bac-cuc-nguyen-quang","name":"Bắc Cực nguyên quang","cn":"北極元光","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Năng lực phòng ngự kết hợp với Lưỡng Nghi hoàn, có thể che chở tối đa ba người xuyên qua khe nứt không gian Trụy Ma Cốc.","detail":"Tuyền Ki Tử giải thích uy lực Lưỡng Nghi hoàn kết hợp Bắc Cực nguyên quang chỉ có thể che chở tối đa ba người, thêm một cũng không được.","congNang":["Kết hợp Lưỡng Nghi hoàn che chở tối đa 3 người vào Trụy Ma Cốc"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ giới hạn uy lực","text":"Tuyền Ki Tử giải thích Lưỡng Nghi hoàn kết hợp Bắc Cực nguyên quang chỉ che chở tối đa ba người, thêm một cũng không được.","anchor":"uy lực của nó nhiều lắm cũng chỉ có thể che chở ba người mà thôi"}]},"nguon":["@c0724"]},{"id":"lam-sac-han-diem","name":"Lam sắc hàn diễm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Hàn Lập"],"blurb":"Hàn diễm màu lam của Hàn Lập, có thể ngưng kết pháp thể tu sĩ Nguyên Anh kỳ trong nháy mắt, được kỳ vọng khắc chế Thiên Lân Yêu Hỏa của Hỏa Thiềm cổ thú.","detail":"Nam Lũng Hầu nhắc lại ấn tượng lam sắc hàn diễm có thể ngưng kết pháp thể tu sĩ Nguyên Anh kỳ, cho rằng có thể khắc chế Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa.","congNang":["Ngưng kết pháp thể tu sĩ Nguyên Anh kỳ trong nháy mắt","Có thể khắc chế hỏa thuộc tính (Thiên Lân Yêu Hỏa)"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc như lý do cần Hàn Lập","text":"Nam Lũng Hầu cho rằng lam sắc hàn diễm có thể khắc chế Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa trong Trụy Ma Cốc.","anchor":"thi triển ra lam sắc hàn diễm, có thể trong nháy mắt ngưng kết pháp thể tu sĩ Nguyên Anh kỳ"}]},"nguon":["@c0724"]},{"id":"thien-lan-yeu-hoa","name":"Thiên Lân Yêu Hỏa","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa thuộc tính","soHuu":["Hỏa Thiềm cổ thú"],"blurb":"Yêu hỏa bẩm sinh của Hỏa Thiềm cổ thú trong Trụy Ma Cốc, mạnh hơn anh hỏa của tu sĩ Nguyên Anh kỳ.","detail":"Yêu hỏa bẩm sinh của loài Hỏa Thiềm cổ thú sống vạn năm trong Trụy Ma Cốc. So với anh hỏa của tu sĩ Nguyên Anh kỳ thì lợi hại hơn nhiều. Thương Khôn Thượng Nhân từng giao thủ sơ đã thua và bị hỏa độc suýt chết.","congNang":["Hỏa lực mạnh hơn anh hỏa tu sĩ Nguyên Anh kỳ","Hỏa độc nguy hiểm, khiến Thương Khôn Thượng Nhân suýt chết"],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lần đầu hé lộ thông tin","text":"Nam Lũng Hầu và Tuyền Ki Tử tiết lộ Hỏa Thiềm cổ thú sở hữu Thiên Lân Yêu Hỏa mạnh hơn anh hỏa Nguyên Anh, Thương Khôn Thượng Nhân từng giao thủ đã thua.","anchor":"yêu hỏa của nó so với anh hỏa của tu sĩ Nguyên Anh chúng ta thì lợi hại hơn nhiều"}]},"nguon":["@c0724"]},{"id":"cam-che-dai-tran-bien-gioi","name":"Cấm chế đại trận","loai":"khac","loaiLabel":"Trận pháp phòng thủ","soHuu":["Cửu Quốc Minh"],"blurb":"Trận pháp phòng thủ do Cửu Quốc Minh bố trí tại hơn mười nơi trọng yếu dọc biên giới, dùng để trì hoãn thế công đại quân pháp sĩ Mộ Lan.","detail":"Dựa vào địa lợi, tổn hao vô số tâm huyết bố trí. Pháp sĩ Mộ Lan phải thanh trừ sạch các nơi có cấm chế đại trận mới coi như chiếm giữ được. Mỗi nơi cần tu sĩ Nguyên Anh tọa trấn.","congNang":["Phòng thủ trì hoãn thế công đại quân"],"tabs":{"tienTrinh":[{"chuong":"@c0725","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang vận hành tại biên giới","text":"Cửu Quốc Minh bố trí cấm chế đại trận tại hơn mười nơi trọng yếu dọc biên giới, dựa vào địa lợi trì hoãn thế công pháp sĩ Mộ Lan. Hàn Lập cùng hai tu sĩ Nguyên Anh được phái tới trấn thủ một trong các nơi đó.","anchor":"dựa vào địa lợi, tổn hao vô số tâm huyết bố trí đại trận cấm chế, trì hoãn thế công của đại quân pháp sĩ một chút"}]},"nguon":["@c0725"]},{"id":"thien-phong-huyen-ba-tran","name":"Thiên phong huyền ba trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Bặc Đà Tử"],"blurb":"Trận pháp do Bặc Đà Tử dùng để chặn đội pháp sĩ Mộ Lan xâm nhập, đã bị phá.","detail":"Trận pháp phòng thủ quy mô lớn dùng để ngăn chặn đội pháp sĩ Mộ Lan. Bặc Đà Tử vận hành trận này nhưng bị phá, bản thân bị thương nặng.","congNang":["Ngăn chặn đội pháp sĩ xâm nhập"],"tabs":{"tienTrinh":[{"chuong":"@c0726","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phá","text":"Bặc Đà Tử dùng trận này chặn pháp sĩ Mộ Lan nhưng trận bị phá, bản thân bị thương nặng.","anchor":"Thiên phong huyền ba trận chẳng lẽ đã bị phá?"}]},"trangThai":"da-pha","capNhatToi":"@c0726","nguon":["@c0726"]},{"id":"dai-tran-luc-sac-vu-hai","name":"Đại trận lục sắc vụ hải Hoàng Long Sơn","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế đại trận","phamCap":"","hePhai":"","soHuu":["Đại hán họ Lục"],"blurb":"Cấm chế đại trận phòng thủ bao phủ hơn mười dặm quanh Hoàng Long Sơn, biểu hiện là lục sắc vụ hải quỷ dị dày đặc.","detail":"Trận pháp phòng thủ quy mô lớn tại Hoàng Long Sơn, kích hoạt bằng chuông xanh. Tạo ra lục sắc vụ hải bao trùm phạm vi hơn mười dặm, có thể mở thông đạo cho người ra vào. Ba Nguyên Anh viện quân đánh giá trận này trước khi vào.","congNang":["Phòng thủ đại bản doanh, tạo lục sắc vụ hải dày đặc bao trùm hơn mười dặm","Có thể mở thông đạo cho người ra vào"],"tabs":{"tienTrinh":[{"chuong":"@c0726","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt","text":"Đại hán họ Lục gõ chuông xanh kích hoạt đại trận, lục sắc vụ hải bao phủ hơn mười dặm quanh Hoàng Long Sơn.","anchor":"bốn phía Hoàng Long Sơn tràn ngập nồng đậm lục sắc quái vụ, đem phương viên trong phạm vi hơn mười dặm hóa thành quỷ dị bích lục vụ hải"}]},"trangThai":"dang-hoat-dong","capNhatToi":"@c0726","nguon":["@c0726"]},{"id":"tu-la-cuc-hoa","name":"Tử La cực hỏa","cn":"","aliases":["Tử La thiên hỏa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa hệ / Hàn hệ","soHuu":["Hàn Lập"],"blurb":"Ma diễm tím do Hàn Lập luyện hóa từ Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công phun hàn khí, uy lực hơn Kiềm Lam Băng Diễm một bậc, là đòn sát thủ lớn nhất hiện tại.","detail":"Hàn Lập mỗi lần luyện hóa một tia Kiềm Lam Băng Diễm thì lập tức chuyển hóa thành ma diễm tím cỡ quả trứng gà. Đặt tên Tử La cực hỏa để phân biệt với Tu La Thánh Hỏa. Uy lực đã mạnh gấp ba so với ban đầu theo nhận xét của Ngân Nguyệt, còn nhiều tiềm lực khai thác. Nguyên Anh Hậu Kỳ tu sĩ bị dính cũng không tiêu thụ nổi, nhưng số lượng hiện rất ít, chưa đủ để đối đầu chính diện Nguyên Anh Hậu Kỳ.","thuocTinh":"Hỏa hệ ma diễm (phái sinh từ hàn khí + dị hỏa)","nguonGoc":"Luyện từ Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công hàn khí","uyLuc":"Hơn Kiềm Lam Băng Diễm một bậc, đã mạnh gấp 3 so với ban đầu, Nguyên Anh Hậu Kỳ bị dính không tiêu thụ nổi","dacDiem":"Ngọn lửa tím cỡ quả trứng gà, số lượng rất ít","congNang":["Ma diễm có thể khiến Nguyên Anh Hậu Kỳ tu sĩ bị dính không tiêu thụ nổi"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0728","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0728","loai":"xuat-hien","importance":"major","giaiDoan":"Luyện thành lần đầu","text":"Hàn Lập dùng Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công phun hàn khí luyện hóa thành ma diễm tím, đặt tên Tử La cực hỏa. Uy lực hơn Kiềm Lam Băng Diễm một bậc, là đòn sát thủ lớn nhất hiện tại. Ngân Nguyệt nhận xét uy lực đã mạnh gấp ba so với lúc mới gặp.","anchor":"Hàn Lập dùng Kiềm Lam Băng Diễm cùng Lục Dực Sương Công phun ra hàn khí mà tu luyện thành ma diễm"}]},"capNhatToi":"@c0728","nguon":["@c0728"]},{"id":"hao-nhien-chinh-khi-quyet","name":"Hạo Nhiên Chính Khí quyết","cn":"浩然正气诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hạo Nhiên Các","soHuu":["Lão giả họ Mã"],"blurb":"Công pháp chính truyền Hạo Nhiên Các, thủy hỏa bất xâm, có tác dụng khắc tà ích quỷ, không bị ma hỏa công tâm.","detail":"Thi triển khi bạch quang nhu hòa hộ thể. Tác dụng thủy hỏa bất xâm, khắc tà ích quỷ. Ưu điểm đặc biệt là không bị ma hỏa công tâm. Tuy nhiên không khắc chế được thiên địa linh hỏa tam vị chân đế.","thuocTinh":"Chính khí","uyLuc":"Thủy hỏa bất xâm, khắc tà ích quỷ, không bị ma hỏa công tâm, nhưng không khắc chế linh hỏa tam vị chân đế","dacDiem":"Bạch quang nhu hòa hộ thể","congNang":["Thủy hỏa bất xâm","Khắc tà ích quỷ","Không bị ma hỏa công tâm"],"nguoiTu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"thi triển","importance":"normal","giaiDoan":"Trận đấu Mã lão giả vs Quật Diệu","text":"Lão giả họ Mã dùng bạch quang nhu hòa hộ thể khi đối đầu Quật Diệu. Cốc Song Bồ phân tích: thủy hỏa bất xâm, khắc tà ích quỷ, không bị ma hỏa công tâm nhưng không khắc chế được thiên địa linh hỏa tam vị chân đế.","anchor":"Hạo Nhiên Chính Khí quyết tựa hồ như thủy hỏa bất xâm, có tác dụng khắc tà ích quỷ"}]},"nguon":["@c0729"]},{"id":"hoa-linh-bien-hoa","name":"Hỏa linh biến hóa","cn":"火灵变化","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thiên địa linh hỏa tam vị chân đế","hePhai":"Bái Hỏa Bộ","soHuu":["Quật Diệu"],"blurb":"Thần thông hỏa thuộc tính đặc thù, luyện hóa Thiên Địa Hỏa Linh thành hỏa mãng, có thể biến hóa thành hỏa giao hồng lân phun xích diễm.","detail":"Hỏa thuộc tính công pháp đạt cảnh giới chí cao, luyện hóa được Thiên Địa Hỏa Linh. Hỏa mãng (Thiên Địa Hỏa Linh ngưng hóa sinh thành) biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo, giương nanh múa vuốt. Không phải Nguyên Anh pháp sĩ phổ thông có thể làm được. Uy lực: hỏa giao phun xích diễm bao phủ cả đối thủ Nguyên Anh lẫn pháp bảo.","thuocTinh":"Hỏa","nguonGoc":"Thiên Địa Hỏa Linh ngưng hóa","uyLuc":"Hỏa giao phun xích diễm cuồn cuộn bao phủ cả đối thủ Nguyên Anh lẫn pháp bảo trong biển lửa","dacDiem":"Hỏa mãng biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo","congNang":["Luyện Thiên Địa Hỏa Linh thành hỏa mãng","Hỏa mãng biến hóa thành hỏa giao hồng lân","Hỏa giao phun xích diễm bao phủ đối thủ"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0729","tangDatToi":"Thiên địa linh hỏa tam vị chân đế","trangThai":"dai-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"thi triển","importance":"major","giaiDoan":"Trận đấu với lão giả họ Mã","text":"Quật Diệu tiết lộ hỏa mãng chính là Thiên Địa Hỏa Linh ngưng hóa sinh thành. Hỏa mãng biến hóa thành hỏa giao hồng lân — mọc sừng, mọc lợi trảo. Hỏa giao phun xích diễm cuồn cuộn bao phủ cả lão giả họ Mã và bát quái đồ trong biển lửa.","anchor":"hỏa mãng hồng quang trên người đại phóng rồi đột nhiên phi vũ thượng thiên, trên đầu sinh ra một cái sừng, vuốt mọc thêm lợi trảo rồi hóa thân thành một con hỏa giao hồng lân"}]},"nguon":["@c0729"]},{"id":"thien-sat-chan-ma-cong","name":"Thiên Sát Chân Ma Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Ma đạo","soHuu":["Hắc bào nhân"],"blurb":"Ma đạo công pháp cực mạnh, ma hoá thân thể cao hai trượng mọc sừng phun nanh, dùng quỷ trảo ẩn hình và đôi lợi trảo tấn công. Tối kiêng kị là kim sắc điện hồ.","detail":"Hắc bào nhân thi triển toàn lực Thiên Sát Chân Ma Công, ma hoá thân thể cao hai trượng, mọc hai sừng, phun răng nanh, toát ra hắc khí kèm tiếng quỷ khóc. Dùng quỷ trảo xanh lục ẩn hình và đôi lợi trảo tấn công. Tự xưng tại cùng cấp hiếm khi gặp đối thủ. Tối kiêng kị của công pháp này là kim sắc điện hồ — được trưởng lão truyền công dặn dò từ khi ban đầu truyền ma công. Bộ dáng ma hoá giống hệt huyễn ảnh trong Lục Cực Chân Ma Công, gợi mối liên hệ giữa hai công pháp ma đạo.","thuocTinh":"Ma đạo","nguonGoc":"Do một trưởng lão truyền công bí ẩn truyền cho hắc bào nhân","uyLuc":"Cực mạnh ở cùng cấp, tự xưng hiếm khi gặp đối thủ","dacDiem":"Tối kiêng kị kim sắc điện hồ. Bộ dáng ma hoá giống hệt huyễn ảnh Lục Cực Chân Ma Công","congNang":["Ma hoá thân thể cao hai trượng, mọc sừng, phun răng nanh, toát hắc khí kèm tiếng quỷ khóc","Quỷ trảo xanh lục ẩn hình tấn công","Đôi lợi trảo bao vây đối thủ","Có thể thu nhỏ thân hình hoặc hoá thành mảnh tơ đen tháo chạy"],"nguoiTu":[{"ten":"Hắc bào nhân","tuChuong":"@c0731","tangDatToi":"Toàn lực","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0731","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hắc bào nhân thi triển toàn lực Thiên Sát Chân Ma Công đấu Hàn Lập, ma hoá thân thể nhưng bị kim sắc điện hồ áp chế, buộc phải hoá thân tháo chạy. Lộ ra tối kiêng kị là kim sắc điện hồ do trưởng lão truyền công dặn dò.","anchor":"Dưới mười phần uy lực của Thiên Sát Chân Ma Công hôm nay của ta"}]},"nguon":["@c0731"]},{"id":"thien-am-huyen-hoa-tran","name":"Thiên Âm Huyễn Hóa Trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đại trận phòng thủ tại Hoàng Long Sơn, được đánh giá rất vững chắc, pháp sĩ Mộ Lan phải tăng gấp rưỡi binh lực mới có thể phá nổi.","detail":"Trận pháp phòng thủ đặt tại Hoàng Long Sơn, tạo vụ hải sương mù bao phủ. Đại hán trọc mi (chỉ huy phòng thủ) đánh giá trận pháp vững chắc, pháp sĩ Mộ Lan không tăng gấp rưỡi thì không thể phá. Có thông đạo mở xuyên vụ hải để ra vào.","congNang":["Tạo vụ hải sương mù phòng thủ bao phủ Hoàng Long Sơn","Pháp sĩ cần tăng gấp rưỡi binh lực mới phá nổi"],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"nhắc tới","importance":"normal","giaiDoan":"Đánh giá phòng thủ","text":"Đại hán trọc mi nhận định trận pháp rất vững chắc, pháp sĩ Mộ Lan không tăng gấp rưỡi thì không phá nổi.","anchor":"Thiên Âm Huyễn Hóa Trận tại Hoàng Long Sơn chúng ta cũng không dễ phá như vậy"}]},"nguon":["@c0732"]},{"id":"truyen-am-mat-thuat","name":"Truyền âm mật thuật","cn":null,"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":null,"hePhai":"Mộ Lan","soHuu":["Cốc Song Bồ","Nhạc thượng sư"],"blurb":"Kỹ thuật truyền âm đặc biệt bảo mật cao hơn truyền âm bình thường, chỉ thần thức cấp Nguyên Anh hậu kỳ mới có thể nghe trộm được.","detail":"Phương thức truyền âm mà Cốc Song Bồ sử dụng để liên lạc bí mật với Nhạc thượng sư (pháp sĩ Mộ Lan ẩn giấu). Khác với truyền âm thông thường, mật thuật này có độ bảo mật cực cao — theo Cốc Song Bồ phán đoán, ngoại trừ thần thức cường đại ngang tu sĩ Nguyên Anh hậu kỳ ra thì không có cách nào nghe trộm được. Hàn Lập đã nghe trộm thành công nhờ thần thức vượt trội so với tu sĩ cùng cấp, qua đó nắm được thông tin tình báo quan trọng về tình hình Mộ Lan.","nguon":["@c0733"]},{"id":"phu-linh-thuat","name":"Phụ linh thuật","cn":"附灵术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật cấm (đã thất truyền)","hePhai":"Không rõ (phe Mộ Lan nắm giữ)","soHuu":["Cốc Song Bồ"],"blurb":"Bí thuật đã thất truyền cho phép tu sĩ hợp nhất với linh thú thành quái vật, đại tăng chiến lực nhưng đại giá là không thể tiến vào luân hồi.","detail":"Cốc Song Bồ thi triển phụ linh thuật hợp nhất với song vĩ phỉ thúy xà, biến thành quái vật nửa người nửa rắn phủ lân phiến xanh biếc, hai đuôi rắn, lưỡi đen. Tu sĩ Nguyên Anh sơ kỳ sau khi thi triển cơ hồ có thể tranh phong với tu sĩ Nguyên Anh trung kỳ. Bí thuật được đồn đã thất truyền từ lâu, đại giá là người dùng không thể tiến vào luân hồi.","thuocTinh":"Hợp nhất người – linh thú","nguonGoc":"Bí thuật cổ đã thất truyền, phe Mộ Lan nắm giữ","yeuCau":"Cần có linh thú tương thích để hợp nhất","uyLuc":"Nguyên Anh sơ kỳ thi triển có thể sánh ngang Nguyên Anh trung kỳ","dacDiem":"Đại giá: không thể tiến vào luân hồi; linh trí quái vật không thấp nhưng kinh nghiệm chiến đấu ít","trangThai":"Đã bị Cốc Song Bồ kích hoạt, quái xà bị Hàn Lập tiêu diệt","congNang":["Hợp nhất tu sĩ với linh thú thành quái vật nửa người nửa thú, đại tăng chiến lực lên gần một đại cảnh giới","Phụ linh vào thú/quái vật nâng tu vi"],"nguoiTu":[{"ten":"Cốc Song Bồ","tuChuong":"@c0734","tangDatToi":"Đã kích hoạt hoàn toàn","trangThai":"Bị tiêu diệt"}],"tabs":{"tienTrinh":[{"chuong":"@c0734","loai":"thi triển","importance":"major","giaiDoan":"Cốc Song Bồ kích hoạt trong cấm chế","text":"Cốc Song Bồ thi triển phụ linh thuật hợp nhất với song vĩ phỉ thúy xà thành quái xà, phá cấm chế thoát ra, bị Hàn Lập đóng băng tiêu diệt.","anchor":"thần thông công pháp không nói, cơ hồ liền có thể cùng tu sĩ trung kỳ phân tranh"},{"chuong":"@c0735","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lần đầu đề cập","text":"Được nhắc đến khi nguyên anh xà quái phụ linh bị Ích Tà Thần Lôi diệt. Là thượng cổ bí thuật cực kỳ ác độc trong ma đạo, bị Ích Tà Thần Lôi khắc chế hoàn toàn.","anchor":"cũng là một loại thượng cổ bí thuật cực kỳ ác độc trong ma đạo"}]},"capNhatToi":"@c0734","nguon":["@c0734","@c0735"]},{"id":"nhu-phong-quyet","name":"Nhu phong quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Nhạc Thượng Sư"],"blurb":"Công pháp tốc độ cực cao mà Nhạc Thượng Sư tu luyện, tự nhận không dưới Lôi Độn Thuật.","detail":"Nhạc Thượng Sư tu luyện công pháp này, tốc độ cực nhanh, tự tin rằng về tốc độ không thua Lôi Độn Thuật của Hàn Lập. Dùng ưu thế tốc độ để giữ khoảng cách, tránh cho đối phương cận chiến.","congNang":["Tốc độ cực cao, không dưới Lôi Độn Thuật"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0736","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0736","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Nhạc Thượng Sư tự tin dùng Nhu phong quyết đối phó Hàn Lập, tuyên bố tốc độ không dưới Lôi Độn Thuật.","anchor":"Ta tu luyện “Nhu phong quyết”, nói về tốc độ quyết sẽ không dưới lôi độn thuật của đối phương"}]},"nguon":["@c0736"]},{"id":"hoa-linh-tinh-nguyen","name":"Hỏa linh tinh nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hỏa","soHuu":["Quật Diệu"],"blurb":"Thủ đoạn hỏa hệ uy lực lớn của Quật Diệu, dùng để phá đại trận.","detail":"Quật Diệu sở hữu hỏa linh tinh nguyên, uy lực phá trận cực lớn. Nhạc Thượng Sư dặn tiết kiệm, chờ thời điểm mấu chốt mới phóng thích.","congNang":["Hỏa hệ cường công phá trận, uy lực cực lớn"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0736","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0736","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Quật Diệu xin phóng thích hỏa linh tinh nguyên phá đại trận Hoàng Long Sơn, được Nhạc Thượng Sư dặn tiết kiệm cho thời điểm mấu chốt.","anchor":"Ta sẽ phóng thích hỏa linh tinh nguyên, một hơi phá đại trận này"}]},"nguon":["@c0736"]},{"id":"linh-thuat-dai-tran","name":"Linh thuật đại trận","cn":"灵术大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Mộ Lan pháp sĩ","soHuu":["Quật Diệu"],"blurb":"Trận pháp đặc trưng của Mộ Lan pháp sĩ, dùng nhiều pháp sĩ thay thế trận kỳ trận bàn để nhanh chóng tạo thành pháp trận linh thuật uy lực cực đại, cần một cao giai pháp sĩ chủ trì.","detail":"Pháp trận linh thuật đặc hữu của Mộ Lan nhân. Thay vì dùng trận kỳ trận bàn, nhiều pháp sĩ hợp lực tụ tập linh khí ngưng tụ thành các nguyên tố cầu khổng lồ (hỏa cầu, v.v.), do cao giai pháp sĩ chủ trì điều khiển. Tại Hỏa Long Sơn, Quật Diệu chủ trì bản hỏa thuộc tính, hơn mười tiểu đội pháp sĩ ngưng thành hơn mười hỏa cầu lao vào phá cấm chế vụ hải.","congNang":["Dùng nhiều pháp sĩ thay trận kỳ tạo pháp trận, tụ linh khí ngưng thành hỏa cầu khổng lồ phá cấm chế"],"nguoiTu":[{"ten":"Quật Diệu","tuChuong":"@c0737","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"thi triển","importance":"major","giaiDoan":"Phá cấm chế Hỏa Long Sơn","text":"Quật Diệu chủ trì linh thuật đại trận hỏa thuộc tính, hơn mười tiểu đội pháp sĩ Mộ Lan ngưng tụ hỏa cầu khổng lồ, sáu lục diện hồng cự phiên bắn quang trụ dẫn hỏa cầu lao vào phá tan cấm chế vụ hải Hỏa Long Sơn.","anchor":"Có thể do sử dụng nhiều pháp sĩ thay thế cho trận kỳ trận bàn, rất nhanh tạo thành pháp trận linh thuật"}]},"nguon":["@c0737"]},{"id":"bach-lien-bi-thuat","name":"Bạch Liên bí thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Mộ Lan pháp sĩ","soHuu":["Nhạc Thượng Sư"],"blurb":"Thần thông thượng cổ, đọc chú ngữ kết ấn hoa sen tạo đóa Bạch Liên trên đầu, triển khai quang mạc bao phủ trăm trượng hình thành bình chướng vô hình ngăn pháp bảo xâm nhập.","detail":"Nữ tử áo xanh đọc thượng cổ chú ngữ tối nghĩa, mười ngón tay kết ấn hoa sen, tạo thành đóa Bạch Liên phiêu đãng trên đầu phát ra bạch sắc linh quang chói mắt. Bạch sắc quang mạc bao phủ phương viên hơn trăm trượng, hình thành bình chướng vô hình chặn đứng kiếm khí Thanh Trúc Phong Vân Kiếm không thể tới gần. Cần thời gian dài niệm chú mới hoàn thành.","congNang":["Tạo bình chướng vô hình phong tỏa khu vực phương viên trăm trượng, ngăn pháp bảo xâm nhập"],"nguoiTu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0739","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0739","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Nữ tử áo xanh đọc thượng cổ chú ngữ, kết ấn hoa sen, tạo đóa Bạch Liên trên đầu triển khai quang mạc trăm trượng, chặn đứng Thanh Trúc Phong Vân Kiếm của Hàn Lập.","anchor":"mười ngón tay tách ra tạo bình như hoa sen, bên trên có một đoàn bạch quang chớp động không thôi"}]},"nguon":["@c0739"]}]};
